166	    public Map<Long, Boolean> checkDdShopAccountUpgrade(List<Long> ddShopAccountIds) {
167	        Map<Long, Boolean> resultMap = ddShopAccountIds.stream().collect(Collectors.toMap(e -> e, e -> true));
168	        List<Partner> partners = ddShopAccountIds.stream().map(e -> Arrays.asList(
169	                new Partner(e, PartnerType.DD_SHOP_ACCOUNT.getIntValue()), new Partner(e, PartnerType.DD_UNIFIED_ACCOUNT.getIntValue())))
170	             .flatMap(Collection::stream).collect(Collectors.toList());
171	        List<WmAdGmvToAdRule> rules = wmKaGmvToAdDomainService.pageGetRulesByTransferAccount(partners, null, -1, 0);
172	        int yesterday = DateTimeUtil.getYesterday();
173	        int hour = DateTimeUtil.getCurrentHour();
174	        for (WmAdGmvToAdRule rule : rules) {
175	            if (rule.getActive() == KaCpsGmvRuleActiveType.VALID.getValue() || rule.getActive() == KaCpsGmvRuleActiveType.FUTURE.getValue()) {
176	                resultMap.put(rule.getToKaAcctId(), false);
177	            }
178	            if (rule.getActive() == KaCpsGmvRuleActiveType.INVALID.getValue()) {
179	                // 如果协议是昨天解约的，那么需要等昨日在途资金转入之后才允许进行升级，这里做个简单卡控
180	                int onBoardDate = DateTimeUtil.unixTimeMill2Date(rule.getOnboardTime() * 1000L);
181	                if (onBoardDate == yesterday && hour < 8) {
182	                    resultMap.put(rule.getToKaAcctId(), false);
183	                }
184	            }
185	        }
186	        
187	        return resultMap;
188	    }
