195	    /**
196	     * 查询可参与随单返的partner和权益信息
197	     * partner命中的配置优先级：时间优先级（新配置的优先级高于老配置）> 实体类型优先级（开店宝Ep账号的配置高于门店）
198	     * @param partners
199	     * @return
200	     */
201	    public Map<Partner, SdfAdAccountActivity> queryPartnerInUseSdfConfig(List<Partner> partners) {
202	        if (CollectionUtils.isEmpty(partners)) {
203	            return Collections.emptyMap();
204	        }
205	
206	        Map<Partner, SdfAdAccountActivity> partnerInUseSdfConfigMap = new HashMap<>();
207	        List<Partner> configPartners = partners.stream()
208	                .filter(e -> e.getPartnerType() == PartnerType.KDB.getIntValue()
209	                        || e.getPartnerType() == PartnerType.POI.getIntValue()
210	                        || e.getPartnerType() == PartnerType.DP_POI.getIntValue())
211	                .collect(Collectors.toList());
212	        int date = DateTimeUtil.getToday();
213	        List<SdfAdAccountActivity> adAccountSdfActivities = adAccountSdfService.getActivityByPartnerAndDate(configPartners, date);
214	
215	        SdfAdAccountActivity kdbEpActivity = null;
216	        // 按照随单返配置时间设置门店或Ep命中的配置
217	        for (SdfAdAccountActivity activity : adAccountSdfActivities) {
218	            Partner partner = new Partner(activity.getPartnerId(), activity.getPartnerType());
219	
220	            if (partner.getPartnerType() == PartnerType.KDB.getIntValue() && kdbEpActivity == null) {
221	                partnerInUseSdfConfigMap.put(partner, activity);
222	                kdbEpActivity = activity;
223	            } else if (partner.getPartnerType() == PartnerType.DP_POI.getIntValue()){
224	                partnerInUseSdfConfigMap.putIfAbsent(partner, kdbEpActivity);
225	            }
226	            partnerInUseSdfConfigMap.putIfAbsent(partner, activity);
227	        }
228	        // 如果有EP维度的随单返配置，并且没有生效的门店维度配置，那么门店命中EP维度的随单返配置
229	        for (Partner partner : configPartners) {
230	            partnerInUseSdfConfigMap.putIfAbsent(partner, kdbEpActivity);
231	        }
232	
233	        return partnerInUseSdfConfigMap.entrySet().stream()
234	                .filter(e -> e.getValue() != null)
235	                .collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue));
236	    }
