253	        SdfAggregateInfo sdfAggregateInfo = new SdfAggregateInfo();
254	        SdfAdAccountActivity adAccountSdfActivity = null;
255	        // 如果协议已经过期，执行过期解约动作，查询当前生效的配置
256	        if (!wmKaGmvToAdDomainService.isSign(rule) && rule != null && rule.getActive() == KaCpsGmvRuleActiveType.VALID.getValue()) {
257	            terminateSdfRule(rule.getRuleId(), SdfAdAccountSignOperateTypeEnum.SYSTEM_TERMINATE.getType(), new SdfSignExtraInfo());
