260	        adAccountSdfActivity = wmKaGmvToAdDomainService.isSign(rule) || ruleId > 0 ?
261	                getSdfAdAccountActivity(rule) : getActivityByEntityAndDate(configPartners, date);
262	
263	        if ((wmKaGmvToAdDomainService.isSign(rule) || ruleId > 0) && rule != null) {
264	            //根据签约数据查询当时签约的配置数据
265	            int endDate = DateTimeUtil.plusDays(rule.getEndDate(), 1);
266	            sdfAggregateInfo.setSdfAccountBills(getSdfAccountBills(partnerId, partnerType, rule.getStartDate(), endDate, rule.getRuleId()));
267	
268	            sdfAggregateInfo.setWmAdGmvToAdRule(rule);
269	            sdfAggregateInfo.setRelatedPoiIds(wmKaGmvToAdDomainService.getRuleRelatedPois(rule.getRuleId(), rule.getActive()));
270	        }
271	
272	        SdfAccountActivityInfo activityInfo = convertToSdfAccountActivityInfo(adAccountSdfActivity, partnerId);
273	        sdfAggregateInfo.setActivityInfo(activityInfo);
274	        sdfAggregateInfo.setSdfAdAccountGray(adAccountSdfService.querySdfGray(configPartners));
275	        return sdfAggregateInfo;
276	    }
