352	    public boolean signSdf(long activityConfigId, long partnerId, int partnerType,
353	                           List<Long> dpShopIds, SdfSignExtraInfo extraInfo, List<Partner> partners, int operateType) throws TException {
354	        String lockKey = "lock_sdf_sign_" + partnerId + "_" + partnerType;
355	        try {
356	            Boolean isLock = kvService.setnxByRedis(lockKey, RedisCategory.COMMON_CATEGORY_TEN_MINUTES, "1", 30);
357	            if (!isLock) {
358	                throw new RuntimeException("当前账号正在签约中，请稍后重试");
359	            }
360	            WmAdGmvToAdRule existRule = wmKaGmvToAdDomainService.getActiveRuleByTransferAccount(partnerId, partnerType);
361	            if (wmKaGmvToAdDomainService.isSign(existRule)) {
362	                throw new RuntimeException("当前账号已存在签约中的协议，不可重复签约");
363	            }
364	            
365	            if (PartnerType.isDDAccount(partnerType) && CollectionUtils.isEmpty(dpShopIds)) {
366	                throw new RuntimeException("签约门店列表为空，不可签约");
367	            }
368	            int date = DateTimeUtil.getToday();
369	            SdfAdAccountActivity activity = adAccountSdfService.getActivityById(activityConfigId);
370	            boolean hitActivity = partners.stream()
371	                    .anyMatch(e -> e.getPartnerId() == activity.getPartnerId() && e.getPartnerType() == activity.getPartnerType());
372	            if (!hitActivity || date < activity.getStartDate() || date > activity.getEndDate()) {
373	                throw new RuntimeException("活动已经失效");
374	            }
375	
376	            WmAdGmvToAdRule rule = buildRule(partnerId, partnerType, extraInfo, activity);
377	            List<WmAdGmvToAdPois> pois = buildWmAdGmvToAdPois(rule, dpShopIds, extraInfo.getAcctId());
378	            int num = wmKaGmvToAdDomainService.createRule(rule, pois);
379	            if (num > 0) {
380	                SdfLaunchStrategy launchStrategy = JsonUtil.parse(activity.getLaunchStrategy(), SdfLaunchStrategy.class);
381	                SdfBenefitRule benefitRule = JsonUtil.parse(activity.getBenefitStrategy(), SdfBenefitRule.class);
382	                SdfCouponInfo couponInfo = benefitRule == null ? null : benefitRule.getSdfCouponInfo();
383	
384	                SdfPostActionParam param = new SdfPostActionParam();
385	                param.setSignId(rule.getRuleId());
386	                param.setPartnerId(rule.getToKaAcctId());
387	                param.setPartnerType(getPartnerTypeByTransferType(rule.getTransferType()));
388	                param.setOperateType(operateType);
389	                param.setLaunchStrategy(launchStrategy);
390	                param.setCouponInfo(couponInfo);
391	                param.setExtraInfo(extraInfo);
392	                param.setActivityConfigId(activity.getId());
393	                postAction(param);
394	            }
395	
396	            return num > 0;
397	        } finally{
398	            //释放锁
399	            kvService.compareAndDelete(lockKey, "1", RedisCategory.COMMON_CATEGORY_TEN_MINUTES);
400	        }
401	    }
