520	                overviewInfoDTOS.add(sdRuleOperateInfoDTO);
521	            }
522	        }
523	        if (!CollectionUtils.isEmpty(historyRules)) {
524	            List<WmAdGmvToAdRuleSnapshot> snapshots = wmKaGmvToAdDomainService.getRuleSnapshotByRuleIds(historyRules.stream()
525	                    .map(WmAdGmvToAdRule::getRuleId).collect(Collectors.toList()));
526	            Map<Long, SdPoiRuleAndOperateInfoDTO> rule2SnapshotMap = snapshots.stream().collect(
527	                    Collectors.toMap(WmAdGmvToAdRuleSnapshot::getRuleId, snapshot -> {
528	                        SdfRuleOverviewInfoDTO overviewInfoDTO = convertToSdfRuleOverviewInfo(snapshot);
529	                        SdPoiRuleAndOperateInfoDTO sdRuleOperateInfoDTO = new SdPoiRuleAndOperateInfoDTO();
530	                        sdRuleOperateInfoDTO.setRuleInfo(overviewInfoDTO);
531	                        sdRuleOperateInfoDTO.setPoiIds(JsonUtil.toList(snapshot.getPoiIds(), Long.class));
532	                        RuleOperateInfo operateInfo = JsonUtil.parse(snapshot.getOperateInfo(), RuleOperateInfo.class);
