763	     * 随单返发放优惠红包
764	     * @param amountChange
765	     */
766	    public AdAccountActivityGrantDetail sdfGrantRedAmount(AccountBalanceAmountChange amountChange, PartnerType partnerType) {
767	        try {
768	            int yesterday = DateTimeUtil.getYesterday();
769	            //查看签约信息
770	            SdfAdAccountSign adAccountOrderBackSign = adAccountSdfService.getAccountSdfSign(amountChange.getPartnerId(), partnerType.getIntValue(), yesterday);
771	            if (adAccountOrderBackSign == null) {
772	                // 查不到签约信息的场景：用户先解约，然后第二天日结之前重新签约相同活动，那么签约信息中的时间周期开始时间会变更为第二天
773	                SdfAdAccountSign adAccountOrderLastSign = adAccountSdfService.getAccountLastSdfSign(amountChange.getPartnerId(), partnerType.getIntValue());
774	                if (adAccountOrderLastSign == null) {
775	                    log.error("sdfGrantRedAmount 随单返签约信息不存在, amountChange:{}", amountChange);
776	                    return null;
777	                }
778	                SdfAdAccountSignOperate sdfAdAccountSignOperate = adAccountSdfService.queryLastTerminateOperateInfo(adAccountOrderLastSign.getId());
779	                if (sdfAdAccountSignOperate == null || sdfAdAccountSignOperate.getCashCycleEndDate() < yesterday) {
780	                    log.error("sdfGrantRedAmount 随单返解约信息不存在, amountChange:{}", amountChange);
781	                    return null;
782	                }
783	                adAccountOrderBackSign = adAccountOrderLastSign;
784	            }
785	            //updateTime转换成日期
786	            int date = DateTimeUtil.unixTimeMill2Date(amountChange.getActionTime() * 1000L);
787	            //判断是否需要返利优惠红包,因为是T+1进行打款，需要减一天
788	            int grantDate = DateTimeUtil.plusDays(date, -1) ;
789	            BigDecimal cashRatioDecimal = adAccountOrderBackSign.getCashRatioDecimal();
790	            BigDecimal redRatioDecimal = getSdfRedPackRatio(adAccountOrderBackSign);
791	            
792	            if (grantDate >= adAccountOrderBackSign.getRedCycleStartDate() &&  grantDate <= adAccountOrderBackSign.getRedCycleEndDate()) {
793	                //获取自动充值活动的预算id
794	                AdCommonGivenRedPacketBudget budget = adAccountGivenRedPacketBudgetAppService.getBudgetByTypeAndDate(BudgetBusinessType.SDF.getCode(), date);
795	                if (budget == null) {
796	                    String content = String.format("随单返发放优惠红包, 没有找到配置的预算id，请及时修改，已经影响当日发放");
797	                    AlarmUtil.DX.notify("[随单返发放优惠红包]", content);
798	                    return null;
799	                }
800	                //存在自动充值活动，计算金额并发放
801	                long grantAmount =  new BigDecimal(amountChange.getAmount()).
802	                        multiply(redRatioDecimal).
803	                        divide(cashRatioDecimal, RoundingMode.HALF_UP).longValue();
804	
805	                if (grantAmount > 0) {
806	                    GrantRedPacketInfo grantRedPacketInfo = trans2GrantRedPacketInfo(amountChange, adAccountOrderBackSign, partnerType, AdFundAccountType.AD_CONMMON_YHHB, grantAmount, date, budget.getId());
807	                    //进行红包发放
808	                    GrantRedPacketResult grantRedPacketResult = adAccountRedPacketActivityAppService.grantRedPacketByFundType(grantRedPacketInfo);
809	                    if (grantRedPacketResult.isSuccess()) {
810	                        return grantRedPacketResult.getDetail();
811	                    }
