969	    public SdfAdAccountSign settingAccountSdfSign(SdfAdAccountActivity adAccountSdfActivity, int date, long partnerId, int partnerType, SdfAdAccountSign lastSignRecord, SdfSignExtraInfo extraInfo) {
970	        SdfBenefitRule rule;
971	        // 如果之前签约过相同的活动，需要取到之前已经累计签约的天数
972	        if (lastSignRecord != null && lastSignRecord.getActivityId() == adAccountSdfActivity.getActivityId()) {
973	            rule = JsonUtil.parse(lastSignRecord.getBenefitStrategy(), SdfBenefitRule.class);
974	            rule = rule == null ? buildInitSdfBenefitRule(adAccountSdfActivity, lastSignRecord) : rule;
975	        } else {
976	            rule = JsonUtil.parse(adAccountSdfActivity.getBenefitStrategy(), SdfBenefitRule.class);
977	            rule = rule == null ? buildInitSdfBenefitRule(adAccountSdfActivity, null) : rule;
978	        }
979	        int redCycleStartDate = date;
980	        int redCycleEndDate = 0;
981	        int cashCycleDate = adAccountSdfActivity.getCashCycleDate();
982	        int redCycleDate = adAccountSdfActivity.getRedCycleDate();
983	        // 计算返红包的开始和结束时间，如果用户签解约后再签约，需要把解约之前已经持续签约的时间扣减掉
984	        if (rule != null && !CollectionUtils.isEmpty(rule.getSdfRedPackStageRules())) {
985	            for (SdfRedPackStage sdfRedPackStage : rule.getSdfRedPackStageRules()) {
986	                int startOffsetDays = sdfRedPackStage.getStartOffsetDays();
987	                int endOffsetDays = sdfRedPackStage.getEndOffsetDays();
988	                int cumulativeSignedDays = sdfRedPackStage.getCumulativeSignedDays();
989	                sdfRedPackStage.setStartDate(DateTimeUtil.plusDays(date, startOffsetDays - cumulativeSignedDays));
990	                sdfRedPackStage.setEndDate(endOffsetDays == -1 ? FOREVER_DAY : Math.min(DateTimeUtil.plusDays(date, endOffsetDays - cumulativeSignedDays), FOREVER_DAY));
991	                redCycleStartDate = Math.min(redCycleStartDate, sdfRedPackStage.getStartDate());
992	                redCycleEndDate = Math.max(redCycleEndDate, sdfRedPackStage.getEndDate());
993	            }
994	        } else {
995	            redCycleStartDate = date;
996	            redCycleEndDate = getEndDate(date, cashCycleDate);
997	        }
998	
999	        SdfAdAccountSign sdfSign = new SdfAdAccountSign();
1000	        sdfSign.setActivityId(adAccountSdfActivity.getActivityId());
1001	        sdfSign.setActivityName(adAccountSdfActivity.getActivityName());
1002	        sdfSign.setSignDate(date);
1003	        sdfSign.setPartnerId(partnerId);
1004	        sdfSign.setPartnerType(partnerType);
1005	        sdfSign.setCashRatio(adAccountSdfActivity.getCashRatio());
1006	        sdfSign.setCashRatioDecimal(adAccountSdfActivity.getCashRatioDecimal());
1007	        sdfSign.setCashCycleStartDate(date);
1008	        sdfSign.setCashCycleEndDate(getEndDate(date, cashCycleDate));
1009	        sdfSign.setRedRatio(adAccountSdfActivity.getRedRatio());
1010	        sdfSign.setRedRatioDecimal(adAccountSdfActivity.getRedRatioDecimal());
1011	        sdfSign.setRedCycleStartDate(redCycleStartDate);
1012	        sdfSign.setRedCycleEndDate(redCycleEndDate);
1013	        sdfSign.setBenefitStrategy(JsonUtil.toJson(rule));
1014	        sdfSign.setStatus(1);
1015	        // 0-应付商家的金额 1-用户实付的订单金额
1016	        sdfSign.setChargeBaseAmountType(1);
1017	        if (!ObjectUtils.isEmpty(extraInfo)) {
1018	            sdfSign.setSignSourceCode(extraInfo.getSignSourceCode());
1019	        }
1020	        return sdfSign;
1021	    }
