1036	    private SdfBenefitRule buildInitSdfBenefitRule(SdfAdAccountActivity activity, SdfAdAccountSign lastSignRecord) {
1037	        SdfBenefitRule rule = new SdfBenefitRule();
1038	        SdfRedPackStage sdfRedPackStage = new SdfRedPackStage();
1039	        sdfRedPackStage.setRatio(activity.getRedRatioDecimal());
1040	        sdfRedPackStage.setStartOffsetDays(0);
1041	        sdfRedPackStage.setEndOffsetDays(activity.getRedCycleDate());
1042	        if (lastSignRecord != null && lastSignRecord.getActivityId() == activity.getActivityId()) {
1043	            sdfRedPackStage.setStartDate(lastSignRecord.getRedCycleStartDate());
1044	            sdfRedPackStage.setEndDate(lastSignRecord.getCashCycleEndDate());
1045	            // 简单处理，解约时间直接使用最近一次更新时间
1046	            SdfAdAccountSignOperate opt = adAccountSdfService.queryLastOperateInfo(lastSignRecord.getId());
1047	            if (opt != null) {
1048	                int terminateDay = DateTimeUtil.unixTimeMill2Date(opt.getCtime() * 1000L);
1049	                sdfRedPackStage.setCumulativeSignedDays(DateTimeUtil.getDiffer(lastSignRecord.getRedCycleStartDate(), terminateDay));
1050	            }
1051	        }
1052	        rule.setSdfRedPackStageRules(Collections.singletonList(sdfRedPackStage));
1053	        return rule;
1054	    }
