1218	            return new Result(false, 1, "随单返签约数据不存在");
1219	        }
1220	        if (SdfAdAccountSignStatusEnum.INVALID.getStatus() == sdfAdAccountSignInfo.getStatus()) {
1221	            return new Result(false, 1, "当前活动已解约,请勿重复操作");
1222	        }
