1319	    public Result importSdfConfigInfo(String fileUrl, int type) {
1320	        try {
1321	            log.info("AdAccountSdfAppService.importSdfActivityConfigInfo url:{}, type:{}", fileUrl, type);
1322	            if (StringUtils.isEmpty(fileUrl)) {
1323	                log.info("AdAccountSdfAppService.importSdfConfigInfo empty url.");
1324	                return new Result(false, 1, "url empty");
1325	            }
1326	            int size = 100000;
1327	            List<String> lines;
1328	            if (fileUrl.startsWith("classpath:")) {
1329	                // 读取classpath下的文件
1330	                String resourcePath = fileUrl.substring(10); // 去掉 "classpath:" 前缀
1331	                lines = Resources.asCharSource(Resources.getResource(resourcePath), Charsets.UTF_8).readLines();
1332	            } else {
1333	                // 校验文件编码格式,不是UTF-8就阻断导入程序
1334	                if (!Charsets.UTF_8.name().equals(ReadCsvFileUtil.detectEncoding(fileUrl))) {
1335	                    log.error("AdAccountSdfAppService.importSdfConfigInfo url file charset isn't UTF-8");
1336	                    return new Result(false, 1, "url file charset isn't UTF-8");
1337	                }
1338	                log.info("AdAccountSdfAppService.importSdfConfigInfo url file charset is UTF-8");
1339	
1340	                // 读取网络文件或本地文件
1341	                lines = Resources.asCharSource(new URL(fileUrl), Charsets.UTF_8).readLines();
1342	            }
1343	            //超过100000行不进行发放
1344	            if (lines.size() > size) {
1345	                log.info("AdAccountSdfAppService.importSdfConfigInfo is size max ,size:{}", lines.size());
1346	                return new Result(false, 1, "url empty");
1347	            }
1348	            if (CollectionUtils.isEmpty(lines)) {
1349	                log.info("AdAccountSdfAppService.importSdfConfigInfo is list is null ,url:{}", fileUrl);
1350	                return new Result(false, 1, "url empty");
1351	            }
1352	            if (type == 1) {
1353	                batchInsert(lines, this::convertActivityAccountList, this::batchCreateSdfActivityAndSign, "活动配置");
1354	            } else if (type == 2) {
1355	                batchInsert(lines, this::convertGrayConfigList, this::createBatchSdfGrayConfig, "白名单配置");
1356	            }
1357	            return new Result(true, 0, "成功");
1358	        } catch (Exception e) {
1359	            log.error("AdAccountSdfAppService.importSdfConfigInfo Exception. url: {}", fileUrl, e);
1360	        }
1361	        return new Result(false, 0, "系统异常");
1362	    }
