1364	    private <T> void batchInsert(List<String> lines, Function<List<String>, List<T>> convertFunction, Function<List<T>, Integer> batchInsertFunction, String remark) throws InterruptedException {
1365	        List<T> list = convertFunction.apply(lines);
1366	        List<List<T>> needLists = com.google.common.collect.Lists.partition(list, 200);
1367	        //200一次遍历插入数据库中
1368	        int success = 0;
1369	        int fail = 0;
1370	        for (List<T> subList : needLists) {
1371	            Integer result = batchInsertFunction.apply(subList);
1372	            success = success + result;
1373	            fail = fail + subList.size() - result;
1374	            // Sleep
1375	            Thread.sleep(ConfigUtilAdapter.getLong(KEY_SYNC_SLEEP_TIME, VAL_SYNC_SLEEP_TIME));
1376	        }
1377	
1378	        log.info("AdAccountSdfAppService.importFile create success. success:{},fail:{}", success, fail);
1379	        String content = String.format("通过文件上传随单返%s, 成功:%d, 失败:%d", remark, success, fail);
1380	        AlarmUtil.DX.notify("[随单返配置]" + remark + "创建(文件)", content);
1381	    }
