1638	                activity.setRedCycleDate(minCycleDate == -1 ? -1 : maxCycleDate);
1639	                activity.setStartDate(configDTO.getStartDate());
1640	                activity.setEndDate(configDTO.getEndDate());
1641	                activity.setStatus(configDTO.getStatus());
1642	                activity.setBenefitStrategy(JsonUtil.toJson(rule));
1643	                activity.setSystemSign(configDTO.getSystemSign());
1644	                activity.setSource(configDTO.getSource());
1645	                if (configDTO.getAdProdType() > 0) {
1646	                    SdfLaunchStrategy launchStrategy = getSdfLaunchStrategyConfig.get(configDTO.getAdProdType());
1647	                    activity.setLaunchStrategy(JsonUtil.toJson(launchStrategy));
1648	                }
1649	                if (activity.getRedCycleDate() == -1) {
1650	                    log.warn("返红包周期不允许配置为-1, accountId:{} activityId:{}", partnerId, activity.getActivityId());
1651	                    continue;
1652	                }
1653	
1654	                accountActivities.add(activity);
1655	            }
1656	        }
1657	        int ret = batchCreateSdfActivityAndSign(accountActivities);
1658	        return ret == accountActivities.size();
1659	    }
