1661	    private void addRedPackStrategy(SdfBenefitRule rule, SdfFeatureConfigDTO featureConfigDTO, BigDecimal redRatio, BigDecimal stage2RedRatio) {
1662	        int redCycleDateStage1 = featureConfigDTO.getRedCycleDate();
1663	        int redCycleDateStage2 = featureConfigDTO.getStage2RedCycleDate();
1664	        int redCycleStartDateStage2 = featureConfigDTO.getStage2RedKeepSignDays();
1665	
1666	        List<SdfRedPackStage> redPackStageRules = new ArrayList<>();
1667	        if (redRatio.compareTo(BigDecimal.ZERO) > 0) {
1668	            SdfRedPackStage item = new SdfRedPackStage();
1669	            item.setRatio(redRatio);
1670	            item.setStartOffsetDays(0);
1671	            item.setEndOffsetDays(redCycleDateStage1 - 1);
1672	            redPackStageRules.add(item);
1673	        }
1674	
1675	        if (stage2RedRatio.compareTo(BigDecimal.ZERO) > 0) {
1676	            SdfRedPackStage item = new SdfRedPackStage();
1677	            item.setRatio(stage2RedRatio);
1678	            item.setStartOffsetDays(redCycleStartDateStage2);
1679	            item.setEndOffsetDays(redCycleDateStage2 == -1 ? -1 : redCycleStartDateStage2 + redCycleDateStage2 - 1);
1680	            redPackStageRules.add(item);
1681	        }
