    public Map<Long, Boolean> checkDdShopAccountUpgrade(List<Long> ddShopAccountIds) {
        Map<Long, Boolean> resultMap = ddShopAccountIds.stream().collect(Collectors.toMap(e -> e, e -> true));
        List<Partner> partners = ddShopAccountIds.stream().map(e -> Arrays.asList(
                new Partner(e, PartnerType.DD_SHOP_ACCOUNT.getIntValue()), new Partner(e, PartnerType.DD_UNIFIED_ACCOUNT.getIntValue())))
             .flatMap(Collection::stream).collect(Collectors.toList());
        List<WmAdGmvToAdRule> rules = wmKaGmvToAdDomainService.pageGetRulesByTransferAccount(partners, null, -1, 0);
        int yesterday = DateTimeUtil.getYesterday();
        int hour = DateTimeUtil.getCurrentHour();
        for (WmAdGmvToAdRule rule : rules) {
            if (rule.getActive() == KaCpsGmvRuleActiveType.VALID.getValue() || rule.getActive() == KaCpsGmvRuleActiveType.FUTURE.getValue()) {
                resultMap.put(rule.getToKaAcctId(), false);
            }
            if (rule.getActive() == KaCpsGmvRuleActiveType.INVALID.getValue()) {
                // 如果协议是昨天解约的，那么需要等昨日在途资金转入之后才允许进行升级，这里做个简单卡控
                int onBoardDate = DateTimeUtil.unixTimeMill2Date(rule.getOnboardTime() * 1000L);
                if (onBoardDate == yesterday && hour < 8) {
                    resultMap.put(rule.getToKaAcctId(), false);
                }
            }
        }

        return resultMap;
    }

    public SdfAdAccountGray getSdfAdAccountGray(long partnerId, int partnerType) {
