    /**
     * 查询可参与随单返的partner和权益信息
     * partner命中的配置优先级：时间优先级（新配置的优先级高于老配置）> 实体类型优先级（开店宝Ep账号的配置高于门店）
     * @param partners
     * @return
     */
    public Map<Partner, SdfAdAccountActivity> queryPartnerInUseSdfConfig(List<Partner> partners) {
        if (CollectionUtils.isEmpty(partners)) {
            return Collections.emptyMap();
        }

        Map<Partner, SdfAdAccountActivity> partnerInUseSdfConfigMap = new HashMap<>();
        List<Partner> configPartners = partners.stream()
                .filter(e -> e.getPartnerType() == PartnerType.KDB.getIntValue()
                        || e.getPartnerType() == PartnerType.POI.getIntValue()
                        || e.getPartnerType() == PartnerType.DP_POI.getIntValue())
                .collect(Collectors.toList());
        int date = DateTimeUtil.getToday();
        List<SdfAdAccountActivity> adAccountSdfActivities = adAccountSdfService.getActivityByPartnerAndDate(configPartners, date);

        SdfAdAccountActivity kdbEpActivity = null;
        // 按照随单返配置时间设置门店或Ep命中的配置
        for (SdfAdAccountActivity activity : adAccountSdfActivities) {
            Partner partner = new Partner(activity.getPartnerId(), activity.getPartnerType());

            if (partner.getPartnerType() == PartnerType.KDB.getIntValue() && kdbEpActivity == null) {
                partnerInUseSdfConfigMap.put(partner, activity);
                kdbEpActivity = activity;
            } else if (partner.getPartnerType() == PartnerType.DP_POI.getIntValue()){
                partnerInUseSdfConfigMap.putIfAbsent(partner, kdbEpActivity);
            }
            partnerInUseSdfConfigMap.putIfAbsent(partner, activity);
        }
        // 如果有EP维度的随单返配置，并且没有生效的门店维度配置，那么门店命中EP维度的随单返配置
        for (Partner partner : configPartners) {
            partnerInUseSdfConfigMap.putIfAbsent(partner, kdbEpActivity);
        }

        return partnerInUseSdfConfigMap.entrySet().stream()
                .filter(e -> e.getValue() != null)
                .collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue));
    }

    public List<Partner> querySdfSignPartners(List<Partner> partners) {
        List<Partner> signPartners = partners.stream().filter(e -> PartnerType.isDDAccount(e.getPartnerType())).collect(Collectors.toList());
        List<WmAdGmvToAdRule> rules = new ArrayList<>();
        for (List<Partner> parts : Lists.partition(signPartners, 1000)) {
            rules.addAll(wmKaGmvToAdDomainService.pageGetRulesByTransferAccount(parts, KaCpsGmvRuleActiveType.VALID.getValue(), 2000, 0));
        }
        return rules.stream().map(e -> new Partner(e.getToKaAcctId(), getPartnerTypeByTransferType(e.getTransferType()))).collect(Collectors.toList());
    }


    public SdfAggregateInfo getSdfAggregateInfo(long ruleId, long partnerId, int partnerType, List<Partner> configPartners) {
        WmAdGmvToAdRule rule = ruleId <= 0 ? wmKaGmvToAdDomainService.getActiveRuleByTransferAccount(partnerId, partnerType) :
                                        wmKaGmvToAdDomainService.getRuleByRuleIdIncludeSnapshot(ruleId);

        int date = DateTimeUtil.getToday();
        SdfAggregateInfo sdfAggregateInfo = new SdfAggregateInfo();
        SdfAdAccountActivity adAccountSdfActivity = null;
        // 如果协议已经过期，执行过期解约动作，查询当前生效的配置
        if (!wmKaGmvToAdDomainService.isSign(rule) && rule != null && rule.getActive() == KaCpsGmvRuleActiveType.VALID.getValue()) {
            terminateSdfRule(rule.getRuleId(), SdfAdAccountSignOperateTypeEnum.SYSTEM_TERMINATE.getType(), new SdfSignExtraInfo());
        }
        // 指定ruleId或者已签状态使用ruleId查询，否则使用partner查询
        adAccountSdfActivity = wmKaGmvToAdDomainService.isSign(rule) || ruleId > 0 ?
                getSdfAdAccountActivity(rule) : getActivityByEntityAndDate(configPartners, date);

        if ((wmKaGmvToAdDomainService.isSign(rule) || ruleId > 0) && rule != null) {
            //根据签约数据查询当时签约的配置数据
            int endDate = DateTimeUtil.plusDays(rule.getEndDate(), 1);
            sdfAggregateInfo.setSdfAccountBills(getSdfAccountBills(partnerId, partnerType, rule.getStartDate(), endDate, rule.getRuleId()));

            sdfAggregateInfo.setWmAdGmvToAdRule(rule);
            sdfAggregateInfo.setRelatedPoiIds(wmKaGmvToAdDomainService.getRuleRelatedPois(rule.getRuleId(), rule.getActive()));
        }

        SdfAccountActivityInfo activityInfo = convertToSdfAccountActivityInfo(adAccountSdfActivity, partnerId);
        sdfAggregateInfo.setActivityInfo(activityInfo);
        sdfAggregateInfo.setSdfAdAccountGray(adAccountSdfService.querySdfGray(configPartners));
        return sdfAggregateInfo;
    }

