    private List<SdfAccountBill> getSdfAccountBills(long partnerId, int partnerType, int startDate, int endDate, long ruleId) {
        List<SdfTransferFlow> flows = getSdfTransferFlows(partnerId, partnerType, startDate, endDate, ruleId, true);
        Map<Integer, Long> date2Amount = flows.stream().collect(Collectors.groupingBy(
                SdfTransferFlow::getDate, Collectors.summingLong(e -> e.getAmount().toFen().longValue())));
        return date2Amount.entrySet().stream().map(e -> {
            SdfAccountBill sdfAccountBill = new SdfAccountBill();
            sdfAccountBill.setDate(e.getKey());
            sdfAccountBill.setTransinAmount(e.getValue());
            sdfAccountBill.setTransoutAmount(e.getValue());
            sdfAccountBill.setGrantAmount(0);
            return sdfAccountBill;
        }).collect(Collectors.toList());
    }


