    public boolean signSdf(long activityConfigId, long partnerId, int partnerType,
                           List<Long> dpShopIds, SdfSignExtraInfo extraInfo, List<Partner> partners, int operateType) throws TException {
        String lockKey = "lock_sdf_sign_" + partnerId + "_" + partnerType;
        try {
            Boolean isLock = kvService.setnxByRedis(lockKey, RedisCategory.COMMON_CATEGORY_TEN_MINUTES, "1", 30);
            if (!isLock) {
                throw new RuntimeException("当前账号正在签约中，请稍后重试");
            }
            WmAdGmvToAdRule existRule = wmKaGmvToAdDomainService.getActiveRuleByTransferAccount(partnerId, partnerType);
            if (wmKaGmvToAdDomainService.isSign(existRule)) {
                throw new RuntimeException("当前账号已存在签约中的协议，不可重复签约");
            }

            if (PartnerType.isDDAccount(partnerType) && CollectionUtils.isEmpty(dpShopIds)) {
                throw new RuntimeException("签约门店列表为空，不可签约");
            }
            int date = DateTimeUtil.getToday();
            SdfAdAccountActivity activity = adAccountSdfService.getActivityById(activityConfigId);
            boolean hitActivity = partners.stream()
                    .anyMatch(e -> e.getPartnerId() == activity.getPartnerId() && e.getPartnerType() == activity.getPartnerType());
            if (!hitActivity || date < activity.getStartDate() || date > activity.getEndDate()) {
                throw new RuntimeException("活动已经失效");
            }

            WmAdGmvToAdRule rule = buildRule(partnerId, partnerType, extraInfo, activity);
            List<WmAdGmvToAdPois> pois = buildWmAdGmvToAdPois(rule, dpShopIds, extraInfo.getAcctId());
            int num = wmKaGmvToAdDomainService.createRule(rule, pois);
            if (num > 0) {
                SdfLaunchStrategy launchStrategy = JsonUtil.parse(activity.getLaunchStrategy(), SdfLaunchStrategy.class);
                SdfBenefitRule benefitRule = JsonUtil.parse(activity.getBenefitStrategy(), SdfBenefitRule.class);
                SdfCouponInfo couponInfo = benefitRule == null ? null : benefitRule.getSdfCouponInfo();

                SdfPostActionParam param = new SdfPostActionParam();
                param.setSignId(rule.getRuleId());
                param.setPartnerId(rule.getToKaAcctId());
                param.setPartnerType(getPartnerTypeByTransferType(rule.getTransferType()));
                param.setOperateType(operateType);
                param.setLaunchStrategy(launchStrategy);
                param.setCouponInfo(couponInfo);
                param.setExtraInfo(extraInfo);
                param.setActivityConfigId(activity.getId());
                postAction(param);
            }

            return num > 0;
        } finally{
            //释放锁
            kvService.compareAndDelete(lockKey, "1", RedisCategory.COMMON_CATEGORY_TEN_MINUTES);
        }
    }

