    public List<WmAdGmvToAdPois> buildWmAdGmvToAdPois(WmAdGmvToAdRule rule, List<Long> poiIdList, long accountId) {
        if (rule == null || org.apache.commons.collections4.CollectionUtils.isEmpty(poiIdList)) {
            return com.google.common.collect.Lists.newArrayList();
        }

        List<WmAdGmvToAdPois> result = com.google.common.collect.Lists.newArrayList();
        for (Long poiId : poiIdList) {
            WmAdGmvToAdPois wmAdGmvToAdPois = new WmAdGmvToAdPois();
            BeanUtils.copyProperties(rule, wmAdGmvToAdPois);
            wmAdGmvToAdPois.setPoiId(poiId)
                    .setConfigOnboardTime(rule.getOnboardTime())
                    .setAffiliateKaAcctId(accountId);
            result.add(wmAdGmvToAdPois);
        }

        return result;
    }

