    private WmAdGmvToAdRule buildRule(long partnerId, int partnerType, SdfSignExtraInfo extraInfo, SdfAdAccountActivity activity) throws TException {
        int startDate = DateTimeUtil.getToday();
        int endDate = activity.getCashCycleDate() == -1 ? NEW_FOREVER_DAY : DateTimeUtil.plusDays(startDate, activity.getCashCycleDate());
        WmAdGmvToAdRule rule = new WmAdGmvToAdRule();
        rule.setExtraInfo("");
        if (PartnerType.isDDAccount(partnerType)) {
            rule.setTransferType(getTransferType(partnerType));
            rule.setMerchantType(KaCpsGmvMerchantType.DD_SDF.getMerchantType());
            RuleExtraInfo ruleExtraInfo = new RuleExtraInfo();
            ruleExtraInfo.setActivityConfigId(activity.getId());
            ruleExtraInfo.setActivityId(activity.getActivityId());
            if (StringUtils.isNotBlank(activity.getBenefitStrategy())) {
                ruleExtraInfo.setSdfBenefitRule(JsonUtil.parse(activity.getBenefitStrategy(), SdfBenefitRule.class));
            }
            rule.setExtraInfo(JsonUtil.toJson(ruleExtraInfo));
        } else {
            throw new RuntimeException("partnerType is not support");
        }
        rule.setRuleId(wmKaGmvToAdDomainService.generateRuleId(Gmv2AdRuleSourceEnum.SDF.getCode())); // TODO修改成枚举
        rule.setDcCustomId(0);
        rule.setDcCustomName(null);
        rule.setMinOrderAmount(0);
        rule.setMaxOrderAmount(0);
        rule.setAdminAccount(Collections.singletonList(extraInfo.getAcctId()));
        rule.setVersion(1);
        rule.setBrandId(0);
        rule.setBrandName(null);
        rule.setStartDate(startDate);
        rule.setEndDate(endDate);
        rule.setFee(0);
        rule.setDeductType(KaCpsGmvRuleDeductType.RATIO.getValue());
        rule.setRatio(activity.getCashRatioDecimal().divide(new BigDecimal(100), 4, RoundingMode.HALF_UP));
        rule.setPoiScopeType(KaCpsGmvRulePoiScopeType.POI.getValue());
        rule.setCeiling(0);
        rule.setCeilingType(AdRuleCeilingType.UN_LIMIT.getValue());
        rule.setToKaAcctId(partnerId);
        rule.setActive(KaCpsGmvRuleActiveType.VALID.getValue());
        rule.setOnboardTime((int) (new Date().getTime() / 1000));
        rule.setOperator(extraInfo.getAccountUserName());
        rule.setSpecificCities(null);
        rule.setFrameId(0);
        rule.setFrameRelatedId(0);
        rule.setBusinessType(KaCpsGmvRuleBusinessType.DD_SDF.getValue());
        rule.setBizLines(null);
        rule.setShippingMethods(null);
        return rule;
    }

