    public PageModel<SdPoiRuleAndOperateInfoDTO> pageGetSdfRule(Long partnerId, List<Integer> partnerTypes, int pageNum, int pageSize, Integer active) {
        PageModel<SdPoiRuleAndOperateInfoDTO> pageModel = new PageModel<>();
        List<SdPoiRuleAndOperateInfoDTO> overviewInfoDTOS = Lists.newArrayList();
        int totalCount = 0;
        KaCpsGmvRuleActiveType activeEnum = KaCpsGmvRuleActiveType.findByValue(active);
        active = activeEnum == null ? null : activeEnum.getValue();

        totalCount = wmKaGmvToAdDomainService.countActiveRulesByTransferType(partnerId, partnerTypes, active);
        int offsetNum = pageNum > 0 ? (pageNum - 1) * pageSize : 0;
        List<Partner> partners = partnerTypes.stream().map(e -> new Partner(partnerId, e)).collect(Collectors.toList());

        List<WmAdGmvToAdRule> rules = wmKaGmvToAdDomainService.pageGetRulesByTransferAccount(partners, active, pageSize, offsetNum);
        List<WmAdGmvToAdRule> activeRules = rules.stream().filter(rule -> rule.getActive() == KaCpsGmvRuleActiveType.VALID.getValue()).collect(Collectors.toList());
        List<WmAdGmvToAdRule> historyRules = rules.stream().filter(rule -> rule.getActive() != KaCpsGmvRuleActiveType.VALID.getValue()).collect(Collectors.toList());
        if (!CollectionUtils.isEmpty(activeRules)) {
            Map<Long, List<Long>> rule2PoiMap = wmKaGmvToAdDomainService.getPoiIdListByRuleIdList(
                    activeRules.stream().map(WmAdGmvToAdRule::getRuleId).collect(Collectors.toList()));
            for (WmAdGmvToAdRule rule : activeRules) {
                SdfRuleOverviewInfoDTO overviewInfoDTO = convertToSdfRuleOverviewInfo(rule);
                SdPoiRuleAndOperateInfoDTO sdRuleOperateInfoDTO = new SdPoiRuleAndOperateInfoDTO();
                sdRuleOperateInfoDTO.setRuleInfo(overviewInfoDTO);
                sdRuleOperateInfoDTO.setPoiIds(rule2PoiMap.getOrDefault(rule.getRuleId(), Collections.emptyList()));
                overviewInfoDTOS.add(sdRuleOperateInfoDTO);
            }
        }
        if (!CollectionUtils.isEmpty(historyRules)) {
            List<WmAdGmvToAdRuleSnapshot> snapshots = wmKaGmvToAdDomainService.getRuleSnapshotByRuleIds(historyRules.stream()
                    .map(WmAdGmvToAdRule::getRuleId).collect(Collectors.toList()));
            Map<Long, SdPoiRuleAndOperateInfoDTO> rule2SnapshotMap = snapshots.stream().collect(
                    Collectors.toMap(WmAdGmvToAdRuleSnapshot::getRuleId, snapshot -> {
                        SdfRuleOverviewInfoDTO overviewInfoDTO = convertToSdfRuleOverviewInfo(snapshot);
                        SdPoiRuleAndOperateInfoDTO sdRuleOperateInfoDTO = new SdPoiRuleAndOperateInfoDTO();
                        sdRuleOperateInfoDTO.setRuleInfo(overviewInfoDTO);
                        sdRuleOperateInfoDTO.setPoiIds(JsonUtil.toList(snapshot.getPoiIds(), Long.class));
                        RuleOperateInfo operateInfo = JsonUtil.parse(snapshot.getOperateInfo(), RuleOperateInfo.class);
                        if (operateInfo != null) {
                            SdfOperateInfoDTO operateInfoDTO = new SdfOperateInfoDTO();
                            operateInfoDTO.setAccountUserName(operateInfo.getAccountUserName());
                            operateInfoDTO.setMis(operateInfo.getMis());
                            operateInfoDTO.setRemark(operateInfo.getRemark());
                            operateInfoDTO.setIp(operateInfo.getIp());
                            operateInfoDTO.setAcctId(operateInfo.getAcctId() == null ? 0 : operateInfo.getAcctId());
                            operateInfoDTO.setOperateType(operateInfo.getOperateType());
                            operateInfoDTO.setToken(operateInfo.getToken());
                            operateInfoDTO.setPlanViewId(operateInfo.getPlanViewId() == null ? 0 : operateInfo.getPlanViewId());
                            operateInfoDTO.setPlatform(operateInfo.getPlatform() == null ? 0 : operateInfo.getPlatform());
                            operateInfoDTO.setOperateTime(snapshot.getCtime());
                            sdRuleOperateInfoDTO.setOperateInfo(operateInfoDTO);
                        }
                        return sdRuleOperateInfoDTO;
                    },(a, b) -> a)
            );
            overviewInfoDTOS.addAll(rule2SnapshotMap.values());
        }
        pageModel.setTotal(totalCount);
        pageModel.setTotalPage((totalCount + pageSize - 1) / pageSize);
        pageModel.setRecords(overviewInfoDTOS);
        pageModel.setPageNo(pageNum);
        pageModel.setPageSize(pageSize);
        return pageModel;
    }


    public Pair<SdfAccountActivityInfo, SdfAdAccountSign> getSdfSignInfo(long partnerId, int partnerType) {
        SdfAdAccountSign adAccountSdfSign = adAccountSdfService.getAccountLastSdfSign(partnerId, partnerType);
        int date = DateTimeUtil.getToday();
        // 如果协议已经过期，执行过期解约动作
        if (adAccountSdfSign != null
                && SdfAdAccountSignStatusEnum.isEffective(adAccountSdfSign.getStatus())
                && adAccountSdfSign.getCashCycleEndDate() < date) {
            terminateSdfSign(adAccountSdfSign, SdfAdAccountSignOperateTypeEnum.SYSTEM_TERMINATE.getType(), null);
        }
        SdfAdAccountActivity adAccountSdfActivity;
        if (!isSign(adAccountSdfSign)) {
            //查询商家是否可参加活动
            adAccountSdfActivity = adAccountSdfService.getActivityByPartnerAndDate(partnerId, partnerType, date);
        } else {
            //根据签约数据查询当时签约的活动数据
            adAccountSdfActivity = adAccountSdfService.getActivityByPartnerAndActivityId(partnerId, partnerType, adAccountSdfSign.getActivityId());
        }
        SdfAccountActivityInfo activityInfo = convertToSdfAccountActivityInfo(adAccountSdfActivity, partnerId);
        return Pair.of(activityInfo, adAccountSdfSign);
    }

    public boolean terminateSdfRule(long ruleId, int operateType, SdfSignExtraInfo extraInfo) {
        String lockKey = "lock_sdf_sign_" + ruleId;
        try {
            Boolean isLock = kvService.setnxByRedis(lockKey, RedisCategory.COMMON_CATEGORY_TEN_MINUTES, "1", 30);
            if (!isLock) {
                throw new RuntimeException("当前协议正在解约中，请稍后重试");
            }

            RuleOperateInfo operateInfo = new RuleOperateInfo();
            BeanUtils.copyProperties(extraInfo, operateInfo);
            operateInfo.setOperateType(operateType);
            WmAdGmvToAdRule rule = wmKaGmvToAdDomainService.getRuleByRuleId(ruleId);
            if (rule == null) {
                return true;
            }

            int ret = wmKaGmvToAdDomainService.closeRule(rule.getRuleId(), operateInfo);
            if (ret > 0) {
                RuleExtraInfo ruleExtraInfo = JsonUtil.parse(rule.getExtraInfo(), RuleExtraInfo.class);
                if (ruleExtraInfo == null) {
                    String info = String.format("extraInfo is null, ruleId=%s&extraInfo=%s", rule.getRuleId(), rule.getExtraInfo());
                    Cat.logEvent("SDF", "PostActionFail", "1", info);
                    log.error("terminateSdfRule error, info:{}", info);
                    return true;
                }
                SdfAdAccountActivity activity = adAccountSdfService.getActivityById(ruleExtraInfo.getActivityConfigId());
                if (activity == null) {
                    String info = String.format("activity is null, ruleId=%s&extraInfo=%s", rule.getRuleId(), rule.getExtraInfo());
                    Cat.logEvent("SDF", "PostActionFail", "1", info);
                    log.error("terminateSdfRule error, info:{}", info);
                    return true;
                }
                SdfLaunchStrategy launchStrategy = JsonUtil.parse(activity.getLaunchStrategy(), SdfLaunchStrategy.class);
                SdfBenefitRule benefitRule = ruleExtraInfo.getSdfBenefitRule();
                SdfCouponInfo couponInfo = benefitRule == null ? null : benefitRule.getSdfCouponInfo();

                SdfPostActionParam param = new SdfPostActionParam();
                param.setSignId(rule.getRuleId());
                param.setPartnerId(rule.getToKaAcctId());
                param.setPartnerType(getPartnerTypeByTransferType(rule.getTransferType()));
                param.setOperateType(operateType);
                param.setLaunchStrategy(launchStrategy);
                param.setCouponInfo(couponInfo);
                param.setExtraInfo(extraInfo);
                postAction(param);

            }
            return ret > 0;
        } catch (Exception e) {
            log.error("AdAccountSdfAppService.terminateSdfSign is error, ruleId:{} operateType:{}", ruleId, operateType, e);
        } finally{
            kvService.compareAndDelete(lockKey, "1", RedisCategory.COMMON_CATEGORY_TEN_MINUTES);
        }

        return false;
    }


    /**
     * 获取商家随单返信息
     * @param partnerId
     * @param partnerType
     */
    public SdfAdAccount getAccountSdfInfo(long partnerId, int partnerType) {
        SdfAdAccount accountSdf = new SdfAdAccount();
        //查询商家签约&活动信息
        Pair<SdfAccountActivityInfo, SdfAdAccountSign> activityAndSignInfo = getSdfSignInfo(partnerId, partnerType);
        SdfAdAccountSign adAccountSdfSign = activityAndSignInfo.getRight();
        SdfAccountActivityInfo activityInfo = activityAndSignInfo.getLeft();
        boolean isSign = isSign(adAccountSdfSign);

        accountSdf.setCanActivity(activityInfo != null);
        accountSdf.setSignFlag(isSign);
        accountSdf.setSdfAccountActivityInfo(activityInfo);
        SdfAdAccountGray gray = adAccountSdfService.querySdfGray(partnerId, partnerType);
        accountSdf.setCanWithdraw(gray != null && gray.getWithdrawType() > 0);
        accountSdf.setCanSelfTermination(gray != null && gray.getTerminationType() > 0);

        if (isSign) {

            //进行账单数据组装
            settingAccountSdfBill(accountSdf, adAccountSdfSign.getActivityId(), partnerId, partnerType, adAccountSdfSign.getCashCycleStartDate(), adAccountSdfSign.getCashCycleEndDate());

            //进行商家随单返整体数据设置
            settingAccountSdfBalance(accountSdf, adAccountSdfSign);
        }
        return accountSdf;
    }

    public boolean isSign(SdfAdAccountSign adAccountSdfSign) {
        int date = DateTimeUtil.getToday();
        return adAccountSdfSign != null 
                && SdfAdAccountSignStatusEnum.isEffective(adAccountSdfSign.getStatus())
                && adAccountSdfSign.getCashCycleStartDate() <= date
                && adAccountSdfSign.getCashCycleEndDate() >= date;
    }

    public Result toggleSdfSign(long partnerId, int partnerType, String activityName, boolean isEffective, int ratio) {
        try {
            log.info("AdAccountSdfAppService.toggleSdfSign request received. partnerId: {}, ratio: {}", partnerId, ratio);

            // 判断是否签约过
            SdfAdAccountSign adAccountOrderBackSign = adAccountSdfService.getAccountLastSdfSign(partnerId, partnerType);
            if (adAccountOrderBackSign == null) {
                int today = DateTimeUtil.getToday();
                billPeriodChangeMafkaProducer.sendMsg(partnerId, BizContractSceneEnum.SDF, 1, DateTimeUtil.currentUnixTime());
                adAccountOrderBackSign = new SdfAdAccountSign();
                adAccountOrderBackSign.setActivityId(today);
                adAccountOrderBackSign.setActivityName(activityName);
                adAccountOrderBackSign.setSignDate(today);
                adAccountOrderBackSign.setPartnerId(partnerId);
                adAccountOrderBackSign.setPartnerType(partnerType);
                adAccountOrderBackSign.setCashCycleStartDate(today);
            }

            // 根据参数设置本次应该修改的数据
            int distantDay = LionUtil.LION.getIntValue("ad_account_sdf.sign_distant_day", 24990101);
            adAccountOrderBackSign.setCashCycleEndDate(distantDay);
            adAccountOrderBackSign.setStatus(isEffective ? 1 : 2);
            // 目前确定业务只能设置 1%、2%... 表里存的是单位是%，上游传的是%后两位
            if (ratio % 100 > 0) {
                log.error("AdAccountSdfAppService.toggleSdfSign unsupported ratio set. partnerId: {}, ratio: {}", partnerId, ratio);
            }
            adAccountOrderBackSign.setCashRatio(ratio / 100);
            adAccountOrderBackSign.setCashRatioDecimal(new BigDecimal(ratio).divide(new BigDecimal(100), 1, RoundingMode.DOWN));

            boolean result = adAccountSdfService.saveSdfSign(SdfAdAccountSignOperateTypeEnum.FULL_SITE_SIGN.getType(), adAccountOrderBackSign, null);
            log.info("AdAccountSdfAppService.toggleSdfSign save. result: {} adAccountOrderBackSign: {}", result, adAccountOrderBackSign);
            if (result) {
                signPostAction(SdfAdAccountSignOperateTypeEnum.SYSTEM_SIGN.getType(), adAccountOrderBackSign, null, null);
                return new Result(true, 0, "success");
            }
        } catch (Exception e) {
            log.error("AdAccountSdfAppService.toggleSdfSign Exception. partnerId: {}, partnerType: {}, activityName: {}, status: {}, ratio: {}",
                    partnerId, partnerType, activityName, isEffective, ratio, e);
        }
        return new Result(false, 1, "未成功设置单返活动！");
    }

    /**
     * 商家随单返签约
     * @param partnerId
     * @param partnerType
     * @return
     */
    public Result saveSdfSign(long partnerId, int partnerType, int operateType, SdfSignExtraInfo extraInfo) {
        try {
            log.info("AdAccountSdfAppService.saveSdfSign is start,partnerId:{}", partnerId);
            //查询是否签约
            SdfAdAccountSign adAccountOrderBackSign =  adAccountSdfService.getAccountLastSdfSign(partnerId, partnerType);
            if (isSign(adAccountOrderBackSign)) {
                return new Result(true, IDEMPOTENT_CODE, "已经签约，重复请求");
            }
            //查询是否存在活动
            int date = DateTimeUtil.getToday();
            SdfAdAccountActivity adAccountOrderBackActivity = adAccountSdfService.getActivityByPartnerAndDate(partnerId, partnerType, date);
            if (adAccountOrderBackActivity == null) {
                return new Result(false, -1, "未查询到商家参与活动");
            }
            //判断是否已经有现金账户，没有直接开户先。店侧partnerId就是广告账户Id，无需再创建账户
            if (!PartnerType.isDDAccount(partnerType)) {
                Map<AdFundAccountType, BalanceDetail> balanceDetailMap = adAccountAppService.queryAllBalance(partnerId, PartnerType.forValue(partnerType), false, false);
                if (balanceDetailMap.get(AdFundAccountType.AD_PRIMARY) == null) {
                    adAccountAppService.createAccount(new AdAccountTuple(partnerId, PartnerType.forValue(partnerType), AdFundAccountType.AD_PRIMARY), "随单返签约");
                }
            }
            SdfAdAccountSign orderBackSign = settingAccountSdfSign(adAccountOrderBackActivity, date, partnerId, partnerType, adAccountOrderBackSign, extraInfo);
            boolean result = adAccountSdfService.saveSdfSign(operateType, orderBackSign, extraInfo);
            log.info("AdAccountSdfAppService.saveSdfSign is end ,partnerId:{}, partnerType:{}, result:{}", partnerId, partnerType, result);
            if (result) {
                signPostAction(operateType, orderBackSign, adAccountOrderBackActivity, extraInfo);
                return new Result(true, 0, "success");
            }

        } catch (Exception e) {
            log.error("AdAccountSdfAppService.saveSdfSign is error, partnerId:{}", partnerId, e);
        }
        return new Result(false, -1, "保存签约失败");
    }

    /**
     * 随单返发放优惠红包
     * @param amountChange
     */
    public AdAccountActivityGrantDetail sdfGrantRedAmount(AccountBalanceAmountChange amountChange, PartnerType partnerType) {
        try {
            int yesterday = DateTimeUtil.getYesterday();
            //查看签约信息
            SdfAdAccountSign adAccountOrderBackSign = adAccountSdfService.getAccountSdfSign(amountChange.getPartnerId(), partnerType.getIntValue(), yesterday);
            if (adAccountOrderBackSign == null) {
                // 查不到签约信息的场景：用户先解约，然后第二天日结之前重新签约相同活动，那么签约信息中的时间周期开始时间会变更为第二天
                SdfAdAccountSign adAccountOrderLastSign = adAccountSdfService.getAccountLastSdfSign(amountChange.getPartnerId(), partnerType.getIntValue());
                if (adAccountOrderLastSign == null) {
                    log.error("sdfGrantRedAmount 随单返签约信息不存在, amountChange:{}", amountChange);
                    return null;
                }
                SdfAdAccountSignOperate sdfAdAccountSignOperate = adAccountSdfService.queryLastTerminateOperateInfo(adAccountOrderLastSign.getId());
                if (sdfAdAccountSignOperate == null || sdfAdAccountSignOperate.getCashCycleEndDate() < yesterday) {
                    log.error("sdfGrantRedAmount 随单返解约信息不存在, amountChange:{}", amountChange);
                    return null;
                }
                adAccountOrderBackSign = adAccountOrderLastSign;
            }
            //updateTime转换成日期
            int date = DateTimeUtil.unixTimeMill2Date(amountChange.getActionTime() * 1000L);
            //判断是否需要返利优惠红包,因为是T+1进行打款，需要减一天
            int grantDate = DateTimeUtil.plusDays(date, -1) ;
            BigDecimal cashRatioDecimal = adAccountOrderBackSign.getCashRatioDecimal();
            BigDecimal redRatioDecimal = getSdfRedPackRatio(adAccountOrderBackSign);

            if (grantDate >= adAccountOrderBackSign.getRedCycleStartDate() &&  grantDate <= adAccountOrderBackSign.getRedCycleEndDate()) {
                //获取自动充值活动的预算id
                AdCommonGivenRedPacketBudget budget = adAccountGivenRedPacketBudgetAppService.getBudgetByTypeAndDate(BudgetBusinessType.SDF.getCode(), date);
                if (budget == null) {
                    String content = String.format("随单返发放优惠红包, 没有找到配置的预算id，请及时修改，已经影响当日发放");
                    AlarmUtil.DX.notify("[随单返发放优惠红包]", content);
                    return null;
                }
                //存在自动充值活动，计算金额并发放
                long grantAmount =  new BigDecimal(amountChange.getAmount()).
                        multiply(redRatioDecimal).
                        divide(cashRatioDecimal, RoundingMode.HALF_UP).longValue();

                if (grantAmount > 0) {
                    GrantRedPacketInfo grantRedPacketInfo = trans2GrantRedPacketInfo(amountChange, adAccountOrderBackSign, partnerType, AdFundAccountType.AD_CONMMON_YHHB, grantAmount, date, budget.getId());
                    //进行红包发放
                    GrantRedPacketResult grantRedPacketResult = adAccountRedPacketActivityAppService.grantRedPacketByFundType(grantRedPacketInfo);
                    if (grantRedPacketResult.isSuccess()) {
                        return grantRedPacketResult.getDetail();
                    }
                }
            }
            return null;
        } catch (Exception e) {
            log.error("AdAccountOrderBackAppService.orderBackGrantRedAmount is error,partnerId:{}", amountChange.getPartnerId(), e);
            return null;
        }
    }

    private BigDecimal getSdfRedPackRatio(SdfAdAccountSign signInfo) {
        int today = DateTimeUtil.getYesterday();

        SdfBenefitRule sdfBenefitRule = JsonUtil.parse(signInfo.getBenefitStrategy(), SdfBenefitRule.class);
        if (sdfBenefitRule != null && !CollectionUtils.isEmpty(sdfBenefitRule.getSdfRedPackStageRules())) {
            BigDecimal redRatioDecimal = BigDecimal.ZERO;
            for (SdfRedPackStage sdfRedPackStage : sdfBenefitRule.getSdfRedPackStageRules()) {
                if (today >= sdfRedPackStage.getStartDate() && today <= sdfRedPackStage.getEndDate()) {
                    redRatioDecimal = redRatioDecimal.add(sdfRedPackStage.getRatio());
                }
            }
            return redRatioDecimal;
        }
        return signInfo.getRedRatioDecimal();
    }

    /**
     * 设置随单返签约信息
     * @param accountSdf
     * @param adAccountSdfActivity
     * @param partnerId
     */
    public void settingAccountSdfActivity(SdfAdAccount accountSdf, SdfAdAccountActivity adAccountSdfActivity, long partnerId) {
        SdfAccountActivityInfo activityInfo = convertToSdfAccountActivityInfo(adAccountSdfActivity, partnerId);
        accountSdf.setSdfAccountActivityInfo(activityInfo);
