    private SdfAccountActivityInfo convertToSdfAccountActivityInfo(SdfAdAccountActivity adAccountSdfActivity, long partnerId) {
        if (adAccountSdfActivity == null) {
            return null;
        }
        SdfAccountActivityInfo activityInfo = new SdfAccountActivityInfo();
        activityInfo.setId(adAccountSdfActivity.getId());
        activityInfo.setCashRatio(adAccountSdfActivity.getCashRatio());
        activityInfo.setRedRatio(adAccountSdfActivity.getRedRatio());
        activityInfo.setCashRatioDecimal(adAccountSdfActivity.getCashRatioDecimal());
        activityInfo.setRedRatioDecimal(adAccountSdfActivity.getRedRatioDecimal());
        activityInfo.setStartDate(adAccountSdfActivity.getStartDate());
        activityInfo.setEndDate(adAccountSdfActivity.getEndDate());
        activityInfo.setCashCycleDate(adAccountSdfActivity.getCashCycleDate());
        activityInfo.setRedCycleDate(adAccountSdfActivity.getRedCycleDate());
        activityInfo.setActivityId(adAccountSdfActivity.getActivityId());
        SdfBenefitRule rule = JsonUtil.parse(adAccountSdfActivity.getBenefitStrategy(), SdfBenefitRule.class);
        if (rule == null) {
            rule = buildInitSdfBenefitRule(adAccountSdfActivity, null);
        }
        activityInfo.setBenefitRule(rule);

        SdfLaunchStrategy launchStrategy = JsonUtil.parse(adAccountSdfActivity.getLaunchStrategy(), SdfLaunchStrategy.class);
        activityInfo.setLaunchStrategy(launchStrategy);

        //获取门店账户信息
        if (adAccountSdfActivity.getPartnerType() == PartnerType.POI.getIntValue()) {
            WmPoiAggre wmPoiAggre = partnerId > 0 ? getPoiAggerInfo(partnerId) : null;
            String poiName = wmPoiAggre == null ? "" : wmPoiAggre.getName();
            activityInfo.setPoiName(poiName);
        }

        activityInfo.setGuidText(adAccountSdfActivity.getGuideText());
        activityInfo.setPartnerId(adAccountSdfActivity.getPartnerId());
        activityInfo.setPartnerType(adAccountSdfActivity.getPartnerType());
        return activityInfo;
    }

    /**
     * 设置商家随单返账期数据
     * @param accountSdf
     * @param date
     * @param partnerId
     * @param partnerType
     * @param cashCycleStartDate
     * @param cashCycleEndDate
     */
    public void settingAccountSdfBill(SdfAdAccount accountSdf, long activityId, long partnerId, int partnerType, int cashCycleStartDate, int cashCycleEndDate) {
        int startTime = DateTimeUtil.getStartUnixTimeByDate(cashCycleStartDate, 0);
        //因T+1日转入，直接往推后2天的0点进行查询
        int endDate = Math.min(DateTimeUtil.plusDays(cashCycleEndDate, 2), FOREVER_DAY);
        int endTime = DateTimeUtil.getStartUnixTimeByDate(endDate, 0);
        int count = wmAdFlowRecordService.countIntelligentAccountAutoRechargeRecords(partnerId, startTime, endTime, BizTypeEnum.POI_AD_IN_BY_ORDER.getValue());
        List<SdfAccountBill> sdfBillList = Lists.newArrayList();
        //没有转入数据直接返回
        if (count == 0 ) {
            accountSdf.setSdfAccountBillList(sdfBillList);
            return;
        }
        //获取商家转入流水
        List<ADFlowRecord> flowRecords = wmAdFlowRecordService.getIntelligentAccountAutoRechargeRecords(partnerId, 0, count, startTime, endTime, BizTypeEnum.POI_AD_IN_BY_ORDER.getValue());
        for (ADFlowRecord adFlowRecord: flowRecords) {
            SdfAccountBill sdfBill = new SdfAccountBill();
            sdfBill.setDate(Integer.valueOf(DateTimeUtil.millisTime2Date(adFlowRecord.getActionTime() * 1000L)));
            sdfBill.setTransinAmount(adFlowRecord.getAmount());
            sdfBill.setTransoutAmount(adFlowRecord.getAmount());
            sdfBillList.add(sdfBill);
        }
        //获取商家发放数据
        List<AdAccountActivityGrantDetail> grantDetails = adAccountRedPacketActivityAppService.getActivityGrantDetailsByPartnerAndActivityId(partnerId, PartnerType.forValue(partnerType),
                activityId, AdGivenRedPacketActivityType.SDF.getActivityType(), AdFundAccountType.AD_CONMMON_YHHB.getIntValue());
        Map<Integer, Long> grantMap = new HashMap();
        if (!CollectionUtils.isEmpty(grantDetails)) {
            for (AdAccountActivityGrantDetail grantDetail : grantDetails) {
                grantMap.put(grantDetail.getDate(), grantDetail.getGrantAmount());
            }
        }
        //进行发放数据设置
        for (SdfAccountBill sdfBill : sdfBillList) {
            int billDate = sdfBill.getDate();
            long grantAmount = grantMap.getOrDefault(billDate, 0L);
            sdfBill.setGrantAmount(grantAmount);
            sdfBill.setTransinAmount(sdfBill.getTransinAmount() + grantAmount);
        }
        accountSdf.setSdfAccountBillList(sdfBillList);
    }

    /**
     * 设置商家随单返余额数据
