    /**
     * 设置商家签约随单返数据
     * @param adAccountSdfActivity
     * @param date
     * @param partnerId
     * @param partnerType
     * @return
     */
    public SdfAdAccountSign settingAccountSdfSign(SdfAdAccountActivity adAccountSdfActivity, int date, long partnerId, int partnerType, SdfAdAccountSign lastSignRecord, SdfSignExtraInfo extraInfo) {
        SdfBenefitRule rule;
        // 如果之前签约过相同的活动，需要取到之前已经累计签约的天数
        if (lastSignRecord != null && lastSignRecord.getActivityId() == adAccountSdfActivity.getActivityId()) {
            rule = JsonUtil.parse(lastSignRecord.getBenefitStrategy(), SdfBenefitRule.class);
            rule = rule == null ? buildInitSdfBenefitRule(adAccountSdfActivity, lastSignRecord) : rule;
        } else {
            rule = JsonUtil.parse(adAccountSdfActivity.getBenefitStrategy(), SdfBenefitRule.class);
            rule = rule == null ? buildInitSdfBenefitRule(adAccountSdfActivity, null) : rule;
        }
        int redCycleStartDate = date;
        int redCycleEndDate = 0;
        int cashCycleDate = adAccountSdfActivity.getCashCycleDate();
        int redCycleDate = adAccountSdfActivity.getRedCycleDate();
        // 计算返红包的开始和结束时间，如果用户签解约后再签约，需要把解约之前已经持续签约的时间扣减掉
        if (rule != null && !CollectionUtils.isEmpty(rule.getSdfRedPackStageRules())) {
            for (SdfRedPackStage sdfRedPackStage : rule.getSdfRedPackStageRules()) {
                int startOffsetDays = sdfRedPackStage.getStartOffsetDays();
                int endOffsetDays = sdfRedPackStage.getEndOffsetDays();
                int cumulativeSignedDays = sdfRedPackStage.getCumulativeSignedDays();
                sdfRedPackStage.setStartDate(DateTimeUtil.plusDays(date, startOffsetDays - cumulativeSignedDays));
                sdfRedPackStage.setEndDate(endOffsetDays == -1 ? FOREVER_DAY : Math.min(DateTimeUtil.plusDays(date, endOffsetDays - cumulativeSignedDays), FOREVER_DAY));
                redCycleStartDate = Math.min(redCycleStartDate, sdfRedPackStage.getStartDate());
                redCycleEndDate = Math.max(redCycleEndDate, sdfRedPackStage.getEndDate());
            }
        } else {
            redCycleStartDate = date;
            redCycleEndDate = getEndDate(date, cashCycleDate);
        }

        SdfAdAccountSign sdfSign = new SdfAdAccountSign();
        sdfSign.setActivityId(adAccountSdfActivity.getActivityId());
        sdfSign.setActivityName(adAccountSdfActivity.getActivityName());
        sdfSign.setSignDate(date);
        sdfSign.setPartnerId(partnerId);
        sdfSign.setPartnerType(partnerType);
        sdfSign.setCashRatio(adAccountSdfActivity.getCashRatio());
        sdfSign.setCashRatioDecimal(adAccountSdfActivity.getCashRatioDecimal());
        sdfSign.setCashCycleStartDate(date);
        sdfSign.setCashCycleEndDate(getEndDate(date, cashCycleDate));
        sdfSign.setRedRatio(adAccountSdfActivity.getRedRatio());
        sdfSign.setRedRatioDecimal(adAccountSdfActivity.getRedRatioDecimal());
        sdfSign.setRedCycleStartDate(redCycleStartDate);
        sdfSign.setRedCycleEndDate(redCycleEndDate);
        sdfSign.setBenefitStrategy(JsonUtil.toJson(rule));
        sdfSign.setStatus(1);
        // 0-应付商家的金额 1-用户实付的订单金额
        sdfSign.setChargeBaseAmountType(1);
        if (!ObjectUtils.isEmpty(extraInfo)) {
            sdfSign.setSignSourceCode(extraInfo.getSignSourceCode());
        }
        return sdfSign;
    }

    private int getEndDate(int date, int offsetDays) {
        if (offsetDays == -1) {
            return FOREVER_DAY;
        }
        int endDate = DateTimeUtil.plusDays(date, offsetDays);
        return Math.min(endDate, FOREVER_DAY);
    }

    /**
     * 新逻辑上线前的活动和签约没有SdfBenefitRule，初始化随单返权益规则兼容这些商家
     * 这部分活动和签约不涉及券发放
     * @return
     */
    private SdfBenefitRule buildInitSdfBenefitRule(SdfAdAccountActivity activity, SdfAdAccountSign lastSignRecord) {
        SdfBenefitRule rule = new SdfBenefitRule();
        SdfRedPackStage sdfRedPackStage = new SdfRedPackStage();
        sdfRedPackStage.setRatio(activity.getRedRatioDecimal());
        sdfRedPackStage.setStartOffsetDays(0);
        sdfRedPackStage.setEndOffsetDays(activity.getRedCycleDate());
        if (lastSignRecord != null && lastSignRecord.getActivityId() == activity.getActivityId()) {
            sdfRedPackStage.setStartDate(lastSignRecord.getRedCycleStartDate());
            sdfRedPackStage.setEndDate(lastSignRecord.getCashCycleEndDate());
            // 简单处理，解约时间直接使用最近一次更新时间
            SdfAdAccountSignOperate opt = adAccountSdfService.queryLastOperateInfo(lastSignRecord.getId());
            if (opt != null) {
                int terminateDay = DateTimeUtil.unixTimeMill2Date(opt.getCtime() * 1000L);
                sdfRedPackStage.setCumulativeSignedDays(DateTimeUtil.getDiffer(lastSignRecord.getRedCycleStartDate(), terminateDay));
            }
        }
        rule.setSdfRedPackStageRules(Collections.singletonList(sdfRedPackStage));
        return rule;
    }

