    /**
     * 随单返解约
     */
    private Result terminateSdfSign(SdfAdAccountSign sdfAdAccountSignInfo, int operateType, SdfSignExtraInfo extraInfo) {
        if (null == sdfAdAccountSignInfo) {
            return new Result(false, 1, "随单返签约数据不存在");
        }
        if (SdfAdAccountSignStatusEnum.INVALID.getStatus() == sdfAdAccountSignInfo.getStatus()) {
            return new Result(false, 1, "当前活动已解约,请勿重复操作");
        }

        // 核心方法 - 修改签约状态为【已失效】
        boolean result = adAccountSdfService.terminateSdfSign(operateType, sdfAdAccountSignInfo, extraInfo);
        if (!result) {
            return new Result(false, 1, "解约随单返失败");
        }

        terminatePostAction(operateType, sdfAdAccountSignInfo, extraInfo);
        // 解约成功 - 发送解约MQ给TSP，目前未定义topic，暂不处理

        return new Result(true, 0, "SUCCESS");
    }

