    private void terminatePostAction(int operateType, SdfAdAccountSign signInfo, @Nullable SdfSignExtraInfo extraInfo) {
        long partnerId = signInfo.getPartnerId();
        int partnerType = signInfo.getPartnerType();
        SdfAdAccountActivity accountActivity = adAccountSdfService.getActivityByPartnerAndActivityId(partnerId, partnerType, signInfo.getActivityId());

        SdfLaunchStrategy launchStrategy = JsonUtil.parse(accountActivity.getLaunchStrategy(), SdfLaunchStrategy.class);
        SdfBenefitRule benefitRule = JsonUtil.parse(signInfo.getBenefitStrategy(), SdfBenefitRule.class);
        SdfCouponInfo  couponInfo = benefitRule == null ? null : benefitRule.getSdfCouponInfo();

        SdfPostActionParam param = new SdfPostActionParam();
        param.setSignId(signInfo.getId());
        param.setPartnerId(partnerId);
        param.setPartnerType(partnerType);
        param.setOperateType(operateType);
        param.setLaunchStrategy(launchStrategy);
        param.setCouponInfo(couponInfo);
        param.setExtraInfo(extraInfo);
        postAction(param);
    }

    private void signPostAction(int operateType, SdfAdAccountSign signInfo, SdfAdAccountActivity accountActivity, @Nullable SdfSignExtraInfo extraInfo) {
        long partnerId = signInfo.getPartnerId();
        int partnerType = signInfo.getPartnerType();
        long signId = signInfo.getId();

        SdfLaunchStrategy launchStrategy = null;
        SdfCouponInfo couponInfo = null;
        if (accountActivity != null) {
            launchStrategy = JsonUtil.parse(accountActivity.getLaunchStrategy(), SdfLaunchStrategy.class);
            SdfBenefitRule benefitRule = JsonUtil.parse(accountActivity.getBenefitStrategy(), SdfBenefitRule.class);
            couponInfo = benefitRule == null ? null : benefitRule.getSdfCouponInfo();
        }
        SdfPostActionParam param = new SdfPostActionParam();
        param.setSignId(signId);
        param.setPartnerId(partnerId);
        param.setPartnerType(partnerType);
        param.setOperateType(operateType);
        param.setLaunchStrategy(launchStrategy);
        param.setCouponInfo(couponInfo);
        param.setExtraInfo(extraInfo);
        postAction(param);
    }

    private void postAction(SdfPostActionParam param) {
        if (param.getOperateType() == SdfAdAccountSignOperateTypeEnum.SYSTEM_SIGN.getType()) {
            adAccountSdfPostActionService.doPostAction(param);
            return;
        }
        ThreadPoolUtil.SDF_POST_ACTION.execute(() -> {
            try {
                adAccountSdfPostActionService.doPostAction(param);
            } catch (Exception e) {
                log.error("AdAccountSdfAppService.postAction is error, param:{}", param, e);
            }
        });
    }

    /**
     * 随单返配置信息导入 1-活动配置 2-白名单配置
     */
    public Result importSdfConfigInfo(String fileUrl, int type) {
        try {
            log.info("AdAccountSdfAppService.importSdfActivityConfigInfo url:{}, type:{}", fileUrl, type);
            if (StringUtils.isEmpty(fileUrl)) {
                log.info("AdAccountSdfAppService.importSdfConfigInfo empty url.");
                return new Result(false, 1, "url empty");
            }
            int size = 100000;
            List<String> lines;
            if (fileUrl.startsWith("classpath:")) {
                // 读取classpath下的文件
                String resourcePath = fileUrl.substring(10); // 去掉 "classpath:" 前缀
                lines = Resources.asCharSource(Resources.getResource(resourcePath), Charsets.UTF_8).readLines();
            } else {
                // 校验文件编码格式,不是UTF-8就阻断导入程序
                if (!Charsets.UTF_8.name().equals(ReadCsvFileUtil.detectEncoding(fileUrl))) {
                    log.error("AdAccountSdfAppService.importSdfConfigInfo url file charset isn't UTF-8");
                    return new Result(false, 1, "url file charset isn't UTF-8");
                }
                log.info("AdAccountSdfAppService.importSdfConfigInfo url file charset is UTF-8");

                // 读取网络文件或本地文件
                lines = Resources.asCharSource(new URL(fileUrl), Charsets.UTF_8).readLines();
            }
            //超过100000行不进行发放
            if (lines.size() > size) {
                log.info("AdAccountSdfAppService.importSdfConfigInfo is size max ,size:{}", lines.size());
                return new Result(false, 1, "url empty");
            }
            if (CollectionUtils.isEmpty(lines)) {
                log.info("AdAccountSdfAppService.importSdfConfigInfo is list is null ,url:{}", fileUrl);
                return new Result(false, 1, "url empty");
            }
            if (type == 1) {
                batchInsert(lines, this::convertActivityAccountList, this::batchCreateSdfActivityAndSign, "活动配置");
            } else if (type == 2) {
                batchInsert(lines, this::convertGrayConfigList, this::createBatchSdfGrayConfig, "白名单配置");
            }
            return new Result(true, 0, "成功");
        } catch (Exception e) {
            log.error("AdAccountSdfAppService.importSdfConfigInfo Exception. url: {}", fileUrl, e);
        }
        return new Result(false, 0, "系统异常");
    }

    private <T> void batchInsert(List<String> lines, Function<List<String>, List<T>> convertFunction, Function<List<T>, Integer> batchInsertFunction, String remark) throws InterruptedException {
        List<T> list = convertFunction.apply(lines);
        List<List<T>> needLists = com.google.common.collect.Lists.partition(list, 200);
        //200一次遍历插入数据库中
        int success = 0;
        int fail = 0;
        for (List<T> subList : needLists) {
            Integer result = batchInsertFunction.apply(subList);
            success = success + result;
            fail = fail + subList.size() - result;
            // Sleep
            Thread.sleep(ConfigUtilAdapter.getLong(KEY_SYNC_SLEEP_TIME, VAL_SYNC_SLEEP_TIME));
        }

        log.info("AdAccountSdfAppService.importFile create success. success:{},fail:{}", success, fail);
        String content = String.format("通过文件上传随单返%s, 成功:%d, 失败:%d", remark, success, fail);
        AlarmUtil.DX.notify("[随单返配置]" + remark + "创建(文件)", content);
    }

    private List<SdfAdAccountActivity> convertActivityAccountList(List<String> lines) {
        List<SdfAdAccountActivity> backActivityAccountList = com.google.common.collect.Lists.newArrayList();
        Map<Integer, SdfLaunchStrategy> getSdfLaunchStrategyConfig = getSdfLaunchStrategyConfig();
        Map<SdfCouponInfo, Long> couponAmountMap = new HashMap<>();
        for (String line : lines) {
            String[] activity = line.split("[|,]");
            if (isHeaderLineByPattern(activity[0])) {
                continue;
            }
            long activityId = Long.valueOf(activity[0].replaceAll("﻿","").trim());
            String activityName = activity[1].replaceAll("﻿","").trim();
            int startDate = Integer.valueOf(activity[2].replaceAll("﻿","").trim());
            int endDate = Integer.valueOf(activity[3].replaceAll("﻿","").trim());
            long accountId = Long.valueOf(activity[4].replaceAll("﻿","").trim());
            int accountType = Integer.valueOf(activity[5].replaceAll("﻿","").trim());
            BigDecimal cashRatioDecimal = new BigDecimal(activity[6].replaceAll("﻿","").trim());
            int cashCycleDate = Integer.valueOf(activity[7].replaceAll("﻿","").trim());
            String couponTemplateIdStr = activity[13].replaceAll("﻿","").trim();
            long couponTemplateId = StringUtils.isBlank(couponTemplateIdStr) ? 0 : Long.valueOf(couponTemplateIdStr);
            String couponInfoIdStr = activity[14].replaceAll("﻿","").trim();
            long benefitTemplateId = StringUtils.isBlank(couponInfoIdStr) ? 0 : Long.valueOf(couponInfoIdStr);

            String adProdTypeStr = activity[15].replaceAll("﻿","").trim();
            int adProdType = StringUtils.isBlank(adProdTypeStr) ? 0 : Integer.valueOf(adProdTypeStr);
            int status = Integer.valueOf(activity[16].replaceAll("﻿","").trim());
            String guidText = activity[17].replaceAll("﻿","").trim();
            // 是否直接签约 1-是 0-不直接签约
            int systemSign = Integer.valueOf(activity[18].replaceAll("﻿","").trim());
            SdfBenefitRule rule = new SdfBenefitRule();
            addRedPackStrategy(rule, activity, 8);
            addCouponStrategy(rule, couponTemplateId, benefitTemplateId, couponAmountMap);
            int maxCycleDate = rule.getSdfRedPackStageRules().stream().map(SdfRedPackStage::getEndOffsetDays).max(Integer::compareTo).orElse(0);
            int minCycleDate = rule.getSdfRedPackStageRules().stream().map(SdfRedPackStage::getEndOffsetDays).min(Integer::compareTo).orElse(0);

            SdfAdAccountActivity accountDO = new SdfAdAccountActivity();
            accountDO.setActivityId(activityId);
            accountDO.setActivityName(activityName);
            accountDO.setStartDate(startDate);
            accountDO.setEndDate(endDate);
            accountDO.setCashRatioDecimal(cashRatioDecimal);
            accountDO.setCashCycleDate(cashCycleDate);
            accountDO.setRedCycleDate(minCycleDate == -1 ? -1 : maxCycleDate);
            accountDO.setBenefitStrategy(JsonUtil.toJson(rule));
            accountDO.setStatus(status);
            accountDO.setGuideText(guidText);
            accountDO.setSystemSign(systemSign);
            switch (accountType) {
                case 1: // 外卖门店
                    accountDO.setPartnerId(accountId);
                    accountDO.setPartnerType(PartnerType.POI.getIntValue());
                    break;
                case 2: // 店侧美团账号ID
//                    accountDO.setMtAccountId(Math.toIntExact(accountId));
                    break;
//                case 3: // 店侧dpShopId
//                    accountDO.setDpShopId(accountId);
                default:
                    break;
            }
            if (adProdType > 0) {
                SdfLaunchStrategy launchStrategy = getSdfLaunchStrategyConfig.get(adProdType);
                accountDO.setLaunchStrategy(JsonUtil.toJson(launchStrategy));
            }
            if (accountDO.getRedCycleDate() == -1) {
                log.warn("返红包周期不允许配置为-1, wmPoiId:{} activityId:{}", accountDO.getPartnerId(), activityId);
                continue;
            }
            backActivityAccountList.add(accountDO);
        }
        return backActivityAccountList;
    }

    private boolean isHeaderLineByPattern(String firstField) {
        // 尝试解析第一个字段为数字，如果失败可能是表头
        try {
            Long.parseLong(firstField.trim());
            return false; // 能解析为数字，不是表头
        } catch (NumberFormatException e) {
            return true; // 不能解析为数字，可能是表头
        }
    }

    private void addRedPackStrategy(SdfBenefitRule rule, String[] activity, int startId) {
        BigDecimal redRatioStage1 = new BigDecimal(activity[startId].replaceAll("﻿","").trim());
        int redCycleDateStage1 = Integer.parseInt(activity[startId + 1].replaceAll("﻿","").trim());
        BigDecimal redRatioStage2 = new BigDecimal(activity[startId + 2].replaceAll("﻿","").trim());
        int redCycleDateStage2 = Integer.valueOf(activity[startId + 3].replaceAll("﻿","").trim());
        int redCycleStartDateStage2 = Integer.valueOf(activity[startId + 4].replaceAll("﻿","").trim());

        List<SdfRedPackStage> redPackStageRules = new ArrayList<>();
        if (redRatioStage1.compareTo(BigDecimal.ZERO) > 0) {
            SdfRedPackStage item = new SdfRedPackStage();
            item.setRatio(redRatioStage1);
            item.setStartOffsetDays(0);
            item.setEndOffsetDays(redCycleDateStage1 - 1);
            redPackStageRules.add(item);
        }

        if (redRatioStage2.compareTo(BigDecimal.ZERO) > 0) {
            SdfRedPackStage item = new SdfRedPackStage();
            item.setRatio(redRatioStage2);
            item.setStartOffsetDays(redCycleStartDateStage2);
            item.setEndOffsetDays(redCycleDateStage2 == -1 ? -1 : redCycleStartDateStage2 + redCycleDateStage2 - 1);
            redPackStageRules.add(item);
        }
        rule.setSdfRedPackStageRules(redPackStageRules);
    }

    private void addCouponStrategy(SdfBenefitRule rule, long couponTemplateId, long benefitTemplateId, Map<SdfCouponInfo, Long> couponAmoutMap) {
        SdfCouponInfo sdfCouponInfo = new SdfCouponInfo();
        sdfCouponInfo.setCouponTemplateId(couponTemplateId);
        sdfCouponInfo.setBenefitTemplateId(benefitTemplateId);
        if (!couponAmoutMap.containsKey(sdfCouponInfo)) {
            long couponAmount = wmCouponProxy.getCouponAmountByTemplateId(couponTemplateId, benefitTemplateId);
            couponAmoutMap.put(sdfCouponInfo, couponAmount);
        }
        sdfCouponInfo.setCouponAmount(couponAmoutMap.get(sdfCouponInfo));
        rule.setSdfCouponInfo(sdfCouponInfo);
    }

