                return ret;
            }
            activityList.stream().filter(activity -> activity.getSystemSign() >= 1).forEach(
                    e -> {
                        Result result = saveSdfSign(e.getPartnerId(), e.getPartnerType(), SdfAdAccountSignOperateTypeEnum.SYSTEM_SIGN.getType(), null);
                        if (!result.isSuccess()) {
                            log.error("[AdAccountSdfAppService.createBatchSdfActivity] saveSdfSign failed with activity:{}", e);
