    // https://km.sankuai.com/collabpage/2729963893
    // source: 204（请求来源，随单返）
    // planType: 3（计划类型，省心推）
    private Map<Integer, SdfLaunchStrategy> getSdfLaunchStrategyConfig() {
        String configStr = ConfigUtilAdapter.getString("sdf_launch_strategy_config", "[{\"adProdType\":35,\"source\": 204,\"planType\": 3,\"launchName\": \"省心推\", \"launchOperateType\": 1}]");
        List<SdfLaunchStrategy> strategies = JsonUtil.parse(configStr, new TypeReference<List<SdfLaunchStrategy>>() {});
        if (CollectionUtils.isEmpty(strategies)) {
