    public boolean updateSdfFeatureConfig(List<SdfFeatureConfigDTO> sdfFeatureConfigDTOS) {
        if (CollectionUtils.isEmpty(sdfFeatureConfigDTOS)) {
            return true;
        }
        Map<Integer, SdfLaunchStrategy> getSdfLaunchStrategyConfig = getSdfLaunchStrategyConfig();
        Map<SdfCouponInfo, Long> couponAmountMap = new HashMap<>();
        List<SdfAdAccountActivity> accountActivities = new ArrayList<>();
        for (SdfFeatureConfigDTO configDTO : sdfFeatureConfigDTOS) {
            // 合法性校验：超过阈值时按阈值处理
            BigDecimal cashRatioInput = new BigDecimal(configDTO.getCashRatio());
            BigDecimal redRatioInput = new BigDecimal(configDTO.getRedRatio());
            BigDecimal stage2RedRatioInput = new BigDecimal(configDTO.getStage2RedRatio());
            BigDecimal cashRatio = cashRatioInput.min(CASH_RATIO_LIMIT);
            BigDecimal redRatio = redRatioInput.min(RED_RATIO_LIMIT);
            BigDecimal stage2RedRatio = stage2RedRatioInput.min(RED_RATIO_LIMIT);
            // 超出阈值时记录错误日志
            if (cashRatioInput.compareTo(CASH_RATIO_LIMIT) > 0) {
                log.error("[SDF] 现金比例超出阈值, accountId:{}, activityId:{}, 输入值:{}, 阈值:{}", configDTO.getPartnerIds(), configDTO.getActivityId(), cashRatioInput, CASH_RATIO_LIMIT);
            }
            if (redRatioInput.compareTo(RED_RATIO_LIMIT) > 0) {
                log.error("[SDF] 红包比例超出阈值, accountId:{}, activityId:{}, 输入值:{}, 阈值:{}", configDTO.getPartnerIds(), configDTO.getActivityId(), redRatioInput, RED_RATIO_LIMIT);
            }
            if (stage2RedRatioInput.compareTo(RED_RATIO_LIMIT) > 0) {
                log.error("[SDF] 二阶段红包比例超出阈值, accountId:{}, activityId:{}, 输入值:{}, 阈值:{}", configDTO.getPartnerIds(), configDTO.getActivityId(), stage2RedRatioInput, RED_RATIO_LIMIT);
            }
            for (Long partnerId : configDTO.getPartnerIds()) {
                SdfBenefitRule rule = new SdfBenefitRule();
                addRedPackStrategy(rule, configDTO, redRatio, stage2RedRatio);
                addCouponStrategy(rule, configDTO, couponAmountMap);
                int maxCycleDate = rule.getSdfRedPackStageRules().stream().map(SdfRedPackStage::getEndOffsetDays).max(Integer::compareTo).orElse(0);
                int minCycleDate = rule.getSdfRedPackStageRules().stream().map(SdfRedPackStage::getEndOffsetDays).min(Integer::compareTo).orElse(0);

                SdfAdAccountActivity activity = new SdfAdAccountActivity();
                activity.setGuideText(configDTO.getGuideText());
                activity.setActivityId(configDTO.getActivityId());
                activity.setActivityName(configDTO.getActivityName());
                activity.setPartnerId(partnerId);
                activity.setPartnerType(configDTO.getPartnerType());
                activity.setCashRatioDecimal(cashRatio);
                activity.setCashCycleDate(configDTO.getCashCycleDate());

                activity.setRedCycleDate(minCycleDate == -1 ? -1 : maxCycleDate);
                activity.setStartDate(configDTO.getStartDate());
                activity.setEndDate(configDTO.getEndDate());
                activity.setStatus(configDTO.getStatus());
                activity.setBenefitStrategy(JsonUtil.toJson(rule));
                activity.setSystemSign(configDTO.getSystemSign());
                activity.setSource(configDTO.getSource());
                if (configDTO.getAdProdType() > 0) {
                    SdfLaunchStrategy launchStrategy = getSdfLaunchStrategyConfig.get(configDTO.getAdProdType());
                    activity.setLaunchStrategy(JsonUtil.toJson(launchStrategy));
                }
                if (activity.getRedCycleDate() == -1) {
                    log.warn("返红包周期不允许配置为-1, accountId:{} activityId:{}", partnerId, activity.getActivityId());
                    continue;
                }

                accountActivities.add(activity);
            }
        }
        int ret = batchCreateSdfActivityAndSign(accountActivities);
        return ret == accountActivities.size();
    }

    private void addRedPackStrategy(SdfBenefitRule rule, SdfFeatureConfigDTO featureConfigDTO, BigDecimal redRatio, BigDecimal stage2RedRatio) {
        int redCycleDateStage1 = featureConfigDTO.getRedCycleDate();
        int redCycleDateStage2 = featureConfigDTO.getStage2RedCycleDate();
        int redCycleStartDateStage2 = featureConfigDTO.getStage2RedKeepSignDays();

        List<SdfRedPackStage> redPackStageRules = new ArrayList<>();
        if (redRatio.compareTo(BigDecimal.ZERO) > 0) {
            SdfRedPackStage item = new SdfRedPackStage();
            item.setRatio(redRatio);
            item.setStartOffsetDays(0);
            item.setEndOffsetDays(redCycleDateStage1 - 1);
            redPackStageRules.add(item);
        }

        if (stage2RedRatio.compareTo(BigDecimal.ZERO) > 0) {
            SdfRedPackStage item = new SdfRedPackStage();
            item.setRatio(stage2RedRatio);
            item.setStartOffsetDays(redCycleStartDateStage2);
            item.setEndOffsetDays(redCycleDateStage2 == -1 ? -1 : redCycleStartDateStage2 + redCycleDateStage2 - 1);
            redPackStageRules.add(item);
        }
        rule.setSdfRedPackStageRules(redPackStageRules);
    }

    private void addCouponStrategy(SdfBenefitRule rule, SdfFeatureConfigDTO featureConfigDTO, Map<SdfCouponInfo, Long> couponAmoutMap) {
        if (featureConfigDTO.getCouponTemplateId() <= 0) {
            return;
        }
        SdfCouponInfo sdfCouponInfo = new SdfCouponInfo();
        sdfCouponInfo.setCouponTemplateId(featureConfigDTO.getCouponTemplateId());
        sdfCouponInfo.setBenefitTemplateId(featureConfigDTO.getBenefitTemplateId());
        if (!couponAmoutMap.containsKey(sdfCouponInfo)) {
            if (featureConfigDTO.getPartnerType() == PartnerType.POI.getIntValue()) {
                long couponAmount = wmCouponProxy.getCouponAmountByTemplateId(featureConfigDTO.getCouponTemplateId(), featureConfigDTO.getBenefitTemplateId());
                couponAmoutMap.put(sdfCouponInfo, couponAmount);
            } else if (featureConfigDTO.getPartnerType() == PartnerType.DP_POI.getIntValue()
                || featureConfigDTO.getPartnerType() == PartnerType.KDB.getIntValue()) {
                Money amount = ddBenefitProxy.getBenefitTemplateAmount(Math.toIntExact(featureConfigDTO.getBenefitTemplateId()), BenefitTypeEnum.DISCOUNT);
                couponAmoutMap.put(sdfCouponInfo, amount.toFen().longValue());
            }
        }
        sdfCouponInfo.setCouponAmount(couponAmoutMap.get(sdfCouponInfo));
        rule.setSdfCouponInfo(sdfCouponInfo);
    }

    /**
     * AI签约随单返
     * @param partnerId        门店ID
     * @param partnerType      门店类型
     * @param operateType      操作类型
     * @param extraInfo        额外信息
     * @return 结果
     */
    public Result aiSignSdf(long partnerId, int partnerType, int operateType, SdfSignExtraInfo extraInfo) {
        log.info("[AdAccountSdfAppService.aiSignSdf] is start,partnerId:{}, partnerType:{}, operateType:{}, extraInfo:{}", partnerId, partnerType, operateType, extraInfo);
        String errorMsg = StringUtils.EMPTY;
        int retryCount = 0;
        // 多次尝试签约随单返
        while (retryCount < LionUtil.LION.getIntValue("sdf_sign_retry_count", 3)) {
            extraInfo.setTryCount(retryCount);
            extraInfo.setSignStatus(true);

            // 调用现有接口实现签约
            Result result = saveSdfSign(partnerId, partnerType, operateType, extraInfo);
            if (result.isSuccess()) {
                log.info("[AdAccountSdfAppService.aiSignSdf] is success,partnerId:{}, partnerType:{}", partnerId, partnerType);
                if (IDEMPOTENT_CODE == result.getCode()) {
                    result.setSuccess(false);
                    errorMsg = result.getMessage();
                    retryCount++;
                    // 幂等成功后不继续重试
                    break;
                } else {
                    return result;
                }
            }
            errorMsg = result.getMessage();
            retryCount++;
        }

        // 重试次数用尽后仍失败
        log.info("[AdAccountSdfAppService.aiSignSdf] is fail,partnerId:{}, partnerType:{}, errorMsg:{}", partnerId, partnerType, errorMsg);
        // 1. 补偿操作记录
        extraInfo.setTryCount(retryCount);
        extraInfo.setSignStatus(false);
        extraInfo.setErrorMsg(errorMsg);
        int rows = adAccountSdfService.saveSignOperate(operateType, extraInfo);
        if (rows != 1) {
            log.error("[AdAccountSdfAppService.aiSignSdf] 补偿操作记录失败, partnerId:{}", partnerId);
        }

        // 2. 大象通知
        String title = "AI外呼签约随单返失败";
        String content = "AI外呼签约随单返失败，签约门店id:" + partnerId + ", 失败原因:" + errorMsg;
        signSdfDXAlarm(title, content);

        // 3. 最终结果
        log.info("[AdAccountSdfAppService.aiSignSdf] end");
        return new Result(false, 1, errorMsg);
    }

    /**
     * 批量查询可签约活动信息
     *
     * @param partnerIdList 门店ID列表
     * @param partnerType   门店类型
     * @return 活动信息
     */
    public List<SdfActivityInfoDTO> batchQueryActiveInfo(List<Long> partnerIdList, int partnerType) {
        List<SdfAdAccountActivity> activityList = adAccountSdfService.batchQueryActiveInfo(partnerIdList, partnerType, DateTimeUtil.getToday());

        List<SdfActivityInfoDTO> dtoList = new ArrayList<>();
        for (SdfAdAccountActivity activity : activityList) {
            SdfActivityInfoDTO dto = new SdfActivityInfoDTO();
            BeanUtils.copyProperties(activity, dto);
            dto.setCashRatioDecimal(String.valueOf(activity.getCashRatioDecimal()));
            dto.setRedRatioDecimal(String.valueOf(activity.getRedRatioDecimal()));
            dto.setPoiId(activity.getPartnerId());
            dtoList.add(dto);
        }
        return dtoList;
    }

    /**
     * 大象通知
     * @param title     标题
     * @param content   内容
     */
    public void signSdfDXAlarm(String title, String content) {
        try {
            boolean dxSwitch = LionUtil.LION.getBooleanValue("sdf_ai_sign_dx_alarm_switch", false);
            List<String> msgGroup = LionUtil.LION.getList("sdf_ai_sign_dx_alarm_mis", String.class, Collections.singletonList("wb_shenwei02"));

            if (dxSwitch && !CollectionUtils.isEmpty(msgGroup)) {
                String[] receivers = msgGroup.toArray(new String[0]);
                AlarmUtil.DX.notifyWithoutJudge(title, content, receivers);
            }
        } catch (Exception e) {
            log.error("AdAccountSdfAppService.signSdfDXAlarm exception, title:{}, content:{}", title, content, e);
        }
    }
}

