@Override
public Result sdfSign(SdfSignReq req) throws TException {
    logger.info("AdAccountSdfAppService.sdfSign is start,partnerId:{} partnerType:{} activityId:{} operateType:{}", 
                req.getPartnerId(), req.getPartnerType(), req.getActivityId(), req.getOperateType());
    SdfSignExtraInfo extraInfo = convertTodSdfSignExtraInfo(req.getExtraInfo());
    if (SdfAdAccountSignOperateTypeEnum.isSign(req.getOperateType())) {
        extraInfo.setRemark("商家自助签约");
        return adAccountSdfAppService.saveSdfSign(req.getPartnerId(), req.getPartnerType(), 
                                                   req.getOperateType(), extraInfo);
    } else if (SdfAdAccountSignOperateTypeEnum.isTerminate(req.getOperateType())) {
        extraInfo.setRemark(req.getOperateType() == 2 ? "商家自助解约" : "解约");
        return adAccountSdfAppService.terminateSdfSign(req.getPartnerId(), req.getPartnerType(), 
                                                       req.getActivityId(), req.getOperateType(), extraInfo);
    }
    return new Result(false, 1, "不支持的操作类型");
}
