public static SdfSignExtraInfo convertTodSdfSignExtraInfo(SdfSignExtraInfoDTO dto) {
    if (dto == null) {
        return new SdfSignExtraInfo();
    }
    SdfSignExtraInfo sdfSignExtraInfo = new SdfSignExtraInfo();
    sdfSignExtraInfo.setIp(dto.getIp());
    sdfSignExtraInfo.setAcctId(dto.getAcctId());
    sdfSignExtraInfo.setPlatform(dto.getPlatform());
    sdfSignExtraInfo.setToken(dto.getToken());
    sdfSignExtraInfo.setPlanViewId(dto.getPlanViewId() > 0 ? dto.getPlanViewId() : null);
    sdfSignExtraInfo.setMis(dto.getMisId());
    sdfSignExtraInfo.setRemark(dto.getRemark());
    sdfSignExtraInfo.setSignSourceCode(dto.getSignSourceCode());
    return sdfSignExtraInfo;
}

