public static int getIntParam(HttpServletRequest request, String paramName) {

    int param = 0;
    if (null != request.getParameter(paramName)){
        param = NumberUtils.toInt(request.getParameter(paramName), 0);
    } else {
        if (null != request.getCookies()){
            Cookie[] cookies = request.getCookies();
            for (Cookie cookie : cookies) {
                if (cookie.getName().equals(paramName)) {
                    param = Integer.valueOf(cookie.getValue());
                }
            }
        }

    }
    return param;
}
```

