package com.sankuai.meituan.waimai.bizad.billing.platform.domain.sdf;

public enum SdfAdAccountSignStatusEnum {
    UN_KNOWN(-1, "未知"),
    EFFECTIVE(1, "生效中"),
    INVALID(2, "无效"),
    EXPIRED(3, "签约活动已过期"),
    ;

    private final int status;

    private final String remark;

    SdfAdAccountSignStatusEnum(int status, String remark) {
        this.status = status;
        this.remark = remark;
    }

    public static SdfAdAccountSignStatusEnum findByStatus(int status) {
        for (SdfAdAccountSignStatusEnum statusEnum : SdfAdAccountSignStatusEnum.values()) {
            if (statusEnum.getStatus() == status) {
                return statusEnum;
            }
        }
        return UN_KNOWN;
    }

    public static boolean isEffective(int status) {
        return status == EFFECTIVE.getStatus();
    }

    public static boolean isTerminated(int status) {
        return status == INVALID.getStatus() || status == EXPIRED.getStatus();
    }

    public int getStatus() {
        return status;
    }

    public String getRemark() {
        return remark;
    }
}

