@Transactional(rollbackFor = Exception.class)
public boolean saveSdfSign(int operateType, SdfAdAccountSign backSign, SdfSignExtraInfo extraInfo) {
    int id =  wmAdAccountSdfSignMapper.insert(backSign);
    if (id < 1) {
        return false;
    }

    int row2 = insertSignOperate(backSign, operateType, extraInfo);
    return row2 > 0;
}

public int querySdfAdAccountSignListTotal(long partnerId, int status) {
    return wmAdAccountSdfSignMapper.querySdfAdAccountSignListTotal(partnerId, status);
}

public List<SdfAdAccountSign> querySdfAdAccountSignList(long partnerId, int status, int pageNum, int pageSize) {
    // 默认分页设置
    pageNum = Math.max(pageNum, 1);
    pageSize = pageSize < 1 ? 20 : pageSize;

    // 获取起始行
    Integer startRow = (pageNum - 1) * pageSize;

    return wmAdAccountSdfSignMapper.querySdfAdAccountSignList(partnerId, status, startRow, pageSize);
}

